INSERT INTO public.questions VALUES ('7c350df7-075f-4228-889f-6dd45fe4c972', 'e8910bdf-b39b-49e9-bd52-5a2b0622036e', 'matrix', 'Questions 15–20', NULL, '<p>Label the map below</p>
<p>Choose the correct letter, <strong>A</strong>–<strong>I,</strong> next to questions 15-20.</p>
<p><img decoding="async" src="data:image/png;base64," width="398" height="374" loading="lazy"></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Fairground rides", "correctCategoryLetter": "I"}, {"itemText": "Entertainment stage", "correctCategoryLetter": "D"}, {"itemText": "Café", "correctCategoryLetter": "A"}, {"itemText": "First aid tent", "correctCategoryLetter": "H"}, {"itemText": "Market stalls", "correctCategoryLetter": "E"}, {"itemText": "Pony rides", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('8d2bf87a-a951-4ddb-8cc0-2db228a39f1d', 'fdfbb0e0-1209-4ede-a0f2-73bf7cb50bb1', 'fillup', 'Questions 37–40', '<p>Complete the summary below.</p>
<p>Write<strong> NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>Singing dunes</strong></p>
<p>Singing dunes, which belong to the type of dunes known as {barchans dunes| barchans}, produce a very loud sound which is transmitted at a low frequency. Researchers have worked out that sand grains fall down the dune and start vibrating against other grains, forming a sound wave.</p>
<p>Research proves that the individual grains have a similar {shape}, but the differences in dimensions alter the {tone}, of the ‘song’. Each grain is covered with a mixture of different {minerals}, and this is vital to the sound production.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>37. Singing dunes, which belong to the type of dunes known as barchans dunes/ barchans , produce a very loud sound…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> barchans dunes | barchans</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “…some <strong>barchans</strong> actually sing.”</li>\n</ul>\n<p><strong>38. Research proves that the individual grains have a similar shape…</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>shape</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Their studies show the grains are a <strong>uniform shape</strong>…”</li>\n</ul>\n<p><strong>39. …but the differences in dimensions alter the tone of the ‘song’.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>tone</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “…the variations in size affect the <strong>tone</strong>.”</li>\n</ul>\n<p><strong>40. Each grain is covered with a mixture of different minerals and this is vital to the sound production.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>minerals</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “…coated with a special veneer… made from a precise combination of <strong>minerals</strong> from surrounding rocks…”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('5b150900-39db-4cda-bd73-495f69d8df47', '61455c9f-22c7-4239-b946-4365ee8f349a', 'radio', 'Questions 31-35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "One limitation of the study was that there were too few subjects involved"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The fact that the subjects in the study came from a similar background was an advantage"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The two experiments should have been carried out in a different order"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The researchers'' choice of a neutral word was helpful in the context of the study"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The study would have been more valid if it had included a range of languages"}]', 'null', 'null', 'null', '[{"content": "<p>31. One limitation of the study was that there were too few subjects involved.</p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong>Đáp án: YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;The first is that the entire study involved <strong>only 62 subjects</strong>&#8230; while the key issue&#8230; was determined by only the <strong>37 remaining subjects</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong>Giải thích:</strong> Tác giả xem số lượng đối tượng tham gia ít ỏi là một <strong>hạn chế</strong> (<strong>limitation</strong>).</p>\n</li>\n</ul>\n<p>32. The fact that the subjects in the study came from a similar background was an advantage.</p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong>Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 3) &#8220;All were female undergraduates&#8230; and their ages and academic qualifications seem remarkably uniform. <strong>Thus, the findings may simply be a product of the nature of the sample</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong>Giải thích:</strong> Tác giả xem tính đồng nhất của mẫu là vấn đề, vì nó khiến kết quả có thể không đại diện, trái ngược với việc là lợi thế.</p>\n</li>\n</ul>\n<p>33. The two experiments should have been carried out in a different order.</p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong>Giải thích:</strong> Có sự phê bình về việc kết hợp dữ liệu từ hai thí nghiệm khác nhau, nhưng <strong>không có thông tin</strong> nào cho rằng thứ tự (order) của chúng là vấn đề.</p>\n</li>\n</ul>\n<p>34. The researchers&#8217; choice of a neutral word was helpful in the context of the study.</p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong>Đáp án: NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong>Dẫn chứng:</strong> (Đoạn 4) &#8220;The researchers intentionally used a ‘neutral’ word so <strong>naturally the subjects found little meaning there</strong>. Clearly, such a methodology <strong>lacks validity</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong>Giải thích:</strong> Việc sử dụng từ trung tính khiến phương pháp luận <strong>thiếu tính hợp lệ</strong> (lacks validity), tức là không hữu ích.</p>\n</li>\n</ul>\n<p>35. The study would have been more valid if it had included a range of languages.</p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong>Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong>Giải thích:</strong> Bài không đề cập đến việc sử dụng nhiều ngôn ngữ (a range of languages) như một cách để tăng tính hợp lệ của nghiên cứu.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('816d59d4-fb32-4e09-a756-68e87308ee51', 'b6e85a44-1d42-41ad-bfb5-f1cba09022cd', 'radio', 'Questions 32-35', '', '<p>Choose<strong> YES</strong> if the statement agrees with the claims of the writer,<strong>NO</strong> if the statement contradicts the claims of the writer,<strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Every country is certain about the best way to expand its tourism sector."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Letting foreign investors build infrastructure allows a government to keep all the profits from tourism."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Mass production of cultural crafts can make the artisans feel disconnected from their work."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The passage states that tourism always improves the living standards of the entire local population."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">32. Every country is certain about the best way to expand its tourism sector. — {NO}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“It has enormous growth potential; almost every country desires an expansion in this sector. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"113\">Yet whether and how to grow is not nearly as straightforward as one might hope</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định mọi quốc gia đều chắc chắn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"59\">certain</em>) về cách tốt nhất để mở rộng ngành du lịch. Tuy nhiên, bài đọc chỉ ra rằng việc có nên phát triển hay phát triển như thế nào (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"193\">whether and how to grow</em>) hoàn toàn không hề dễ dàng/thẳng thắn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"257\">not nearly as straightforward</em>) như người ta kỳ vọng. Sự thiếu đồng nhất và phức tạp này mâu thuẫn hoàn toàn với từ \"certain\". Đáp án là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"393\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">33. Letting foreign investors build infrastructure allows a government to keep all the profits from tourism. — {NO}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“Alternatively, the government may attract <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"63\">foreign investment, allowing others to pay for the building, thus relieving itself of providing capital but forgoing profits</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói việc để nhà đầu tư nước ngoài xây hạ tầng sẽ giúp chính phủ giữ lại toàn bộ lợi nhuận (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"111\">keep all the profits</em>). Nhưng bài đọc viết rõ: khi để bên khác bỏ vốn xây dựng, chính phủ sẽ nhẹ gánh được phần vốn ban đầu nhưng bù lại phải <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"252\">từ bỏ/mất đi phần lợi nhuận</strong> (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"281\">forgoing profits</strong>). Vì thông tin trái ngược hoàn toàn nên đáp án là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"348\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">34. Mass production of cultural crafts can make the artisans feel disconnected from their work. — {YES}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Yet commodities can be <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"44\">produced most efficiently using industrial machinery to take advantage of economies of scale [mass production]</strong>... <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"158\">This alienates the producers from what is being produced</strong>, and means the product no longer has any personal meaning to them.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Mass production\" (sản xuất hàng loạt) tương ứng với cụm \"produced most efficiently using industrial machinery to take advantage of economies of scale\". \"Artisans / producers\" (nghệ nhân / nhà sản xuất). Cụm từ \"feel disconnected from their work\" (cảm thấy bị mất kết nối/xa rời công việc) đồng nghĩa hoàn toàn với động từ làm cho xa lánh, cách biệt (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"363\">alienates the producers from what is being produced</strong>). Đáp án là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"427\">YES</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">35. The passage states that tourism always improves the living standards of the entire local population. — {NO}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Even when successful, <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"43\">tourism often concentrates wealth and benefits in specific, developed enclaves, failing to distribute them widely across the local population</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định du lịch <em data-path-to-node=\"11,1,0\" data-index-in-node=\"39\">luôn luôn</em> cải thiện mức sống của <em data-path-to-node=\"11,1,0\" data-index-in-node=\"72\">toàn bộ</em> người dân địa phương (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"102\">always... entire local population</em>). Trong khi đó, bài đọc lập luận rằng du lịch thường tập trung của cải và lợi ích vào các đặc khu biệt lập, <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"244\">thất bại trong việc phân chia rộng rãi cho người dân bản địa</strong> (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"306\">failing to distribute them widely</em>). Do đó, luận điểm này hoàn toàn sai lệch so với bài viết. Đáp án là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"409\">NO</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('1a6ec384-418d-44c8-bef7-ecd67ca5675b', 'd96d2ec4-17d6-40d7-a9a8-138c13df16aa', 'matching', 'Question 16-20', '', '<p>What is the current feature of traffic management in each of the following cities<br>Write the correct letter, <strong>A-H</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Cities</strong></p>\n<p> </p>\n<p>London {good signage}</p>\n<p> </p>\n<p>Edinburgh {Effective traffic lights}</p>\n<p> </p>\n<p>Cardiff {Additional lanes}</p>\n<p> </p>\n<p>manchester {ring roads}</p>\n<p> </p>\n<p>oxford {multiple access roads}</p>", "answerOptions": [{"optionText": "good signage"}, {"optionText": "multiple access roads"}, {"optionText": "police control points"}, {"optionText": "ring roads"}, {"optionText": "one- way streets"}, {"optionText": "Effective traffic lights"}, {"optionText": "Additional lanes"}, {"optionText": "Pedestrianised areas"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('a4562753-98c1-4503-b668-4f2246548e1e', 'ca19f140-6fc3-4bb7-b56e-c264302b0b2c', 'radio', 'Questions 27-31', NULL, '<p>Choose the correct letter, <strong>A, B, C </strong>or <strong>D</strong>. Write the correct letter in boxes 27-31 on your answer sheet.</p>
', 'multiple-choice', '[{"correct": 3, "options": [{"content": "A. underestimated the role of family played in Stevenson’s life."}, {"content": "B. overestimated the writer’s works in the literature history."}, {"content": "C. exaggerated Stevenson’s religious belief in his works."}, {"content": "D. elevated Stevenson’s role as a writer."}], "question": "Stevenson’s biographers KF and CP"}, {"correct": 3, "options": [{"content": "A. the public give a more fair criticism to Stevenson’s works."}, {"content": "B. recent criticism has been justified."}, {"content": "C. the style of Stevenson’s works overweigh his faults in his life."}, {"content": "D. Stevenson’s works’ drawback is lack of ethical nature."}], "question": "The main point of the second paragraph is"}, {"correct": 1, "options": [{"content": "A. do not provide plot twists well."}, {"content": "B. cannot be used by writers to show moral values."}, {"content": "C. are more fashionable art form."}, {"content": "D. can be found in other’s works but not in Stevenson’s."}], "question": "According to the author, adventure stories"}, {"correct": 0, "options": [{"content": "A. They describe the life of people in Scotland."}, {"content": "B. They are commonly regarded as real literature."}, {"content": "C. They were popular during Stevenson’s life."}, {"content": "D. They transcend the local culture and stories."}], "question": "What does the author say about Stevenson’s works?"}, {"correct": 2, "options": [{"content": "A. made his family envy him so much."}, {"content": "B. should be responsible for his death."}, {"content": "C. gained more attention from the public than his works."}, {"content": "D. didn’t well prepare his life in Samoa."}], "question": "The lifestyle of Stevenson"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">27. Stevenson’s biographers KF and CP</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: D. elevated Stevenson’s role as a writer.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 1, câu cuối: <em data-path-to-node=\"3,1,0\" data-index-in-node=\"29\">“Instead, they focused on his writing, and <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"72\">gave high praise to his writing style and skill</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì chỉ trích đời tư, hai nhà tiểu sử KF và CP tập trung vào việc ca ngợi phong cách và kỹ năng viết lách của Stevenson. Hành động này giúp nâng cao vị thế và vai trò của ông với tư cách là một nhà văn trong mắt công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. The main point of the second paragraph is</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: D. Stevenson’s works’ drawback is lack of ethical nature.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2: <em data-path-to-node=\"6,1,0\" data-index-in-node=\"19\">“…he became an example of an author with <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"62\">corrupt ethics and lack of moral</strong>… many critics still assert that despite his skill, his literary works still <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"173\">lack moral value</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nội dung chính của đoạn 2 xoay quanh những ý kiến tiêu cực cho rằng các tác phẩm của Stevenson thiếu đi giá trị đạo đức hoặc có nội dung suy đồi. Đây được coi là điểm yếu lớn nhất (<strong data-path-to-node=\"6,2,0\" data-index-in-node=\"193\">drawback</strong>) khiến tác phẩm của ông bị loại khỏi chương trình giảng dạy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. According to the author, adventure stories</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: B. cannot be used by writers to show moral values.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3: <em data-path-to-node=\"9,1,0\" data-index-in-node=\"19\">“Many of us believe adventure stories… ultimately <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"71\">can’t teach moral principles</strong>. The plot points are one-dimensional and <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"141\">rarely offer a deeper moral meaning</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả phân tích rằng thể loại truyện phiêu lưu mà Stevenson theo đuổi thường bị đánh giá là nông cạn, chỉ tập trung vào các tình tiết giật gân, ly kỳ mà không có khả năng truyền tải hay giáo dục các giá trị đạo đức sâu sắc cho người đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">30. What does the author say about Stevenson’s works?</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: A. They describe the life of people in Scotland.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4: <em data-path-to-node=\"12,1,0\" data-index-in-node=\"19\">“Stevenson’s works… <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"41\">captured the unique day to day life of average Scottish people</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một đặc điểm nổi bật trong tác phẩm của Stevenson được tác giả nhắc đến là khả năng mô tả chân thực và sống động cuộc sống hàng ngày của tầng lớp bình dân tại Scotland vào thế kỷ 19, mang lại những hiểu biết giá trị về văn hóa địa phương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. The lifestyle of Stevenson</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: C. gained more attention from the public than his works.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5: <em data-path-to-node=\"15,1,0\" data-index-in-node=\"19\">“Some even argue that his <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"45\">personal life eventually outshone his writing</strong>… interest in Stevenson’s life had <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"127\">taken the place of interest in his works</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Do cuộc đời của Stevenson có nhiều biến cố (sức khỏe yếu, chuyển đến sống tại đảo Samoa, sở thích du hành), công chúng thường có xu hướng quan tâm và bàn tán về lối sống của ông nhiều hơn là tập trung vào giá trị các tác phẩm văn học mà ông để lại.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('bb58d080-feab-45d9-ae11-e9f1a0835643', 'c0760ea7-11fa-4c27-ab40-cb7bc18a3546', 'matching', 'Questions 27-32', NULL, '<p>Complete the summary using the list of words. Choose the correct answer and move it into the gap.</p>', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Provine''s early findings on yawns</strong></p>\n<p>Through his observation of yawns, Province was able to confirm that {half-yawns} do not exist.</p>\n<p>Just like a {sneeze}, yawns cannot be interrupted after they have begun. This is because yawns occur as a {fixed action pattern} rather than a stimulus response as was previously thought.</p>\n<p>In measuring the time taken to yawn, provive found that a typical yawn lasts about {6 seconds}. He also found that it is a common for people to yawn a number of times in quick succession with the yawns usually being around {68 seconds} apart. </p>\n<p>When studying whether length and rate were connected, Province concluded that people who yawn less do not necessarily produce {long yawns} to make up for this.</p>", "answerOptions": [{"optionText": "form and function"}, {"optionText": "long yawns"}, {"optionText": "3 seconds"}, {"optionText": "fixed action pattern"}, {"optionText": "68 seconds"}, {"optionText": "short yawns"}, {"optionText": "reflex"}, {"optionText": "sneeze"}, {"optionText": "short duration"}, {"optionText": "6 seconds"}, {"optionText": "half-yawns"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. Provine was able to confirm that {K: half-yawns} do not exist.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “There are no <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"25\">half-yawns</strong>: this is an example of the typical intensity of fixed action patterns…” (Đoạn 4).</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định không tồn tại cái gọi là “ngáp một nửa” vì đây là một mô hình hành động cố định.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. Just like a {H: sneeze}, yawns cannot be interrupted after they have begun.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…but, once started, a yawn progresses with the inevitability of a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"80\">sneeze</strong>.” (Đoạn 4).</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một khi đã bắt đầu, cơn ngáp sẽ diễn ra cho đến hết, giống hệt như một cái <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"87\">hắt hơi (sneeze)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. This is because yawns occur as a {D: fixed action pattern} rather than a stimulus response.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It is an excellent example of the instinctive <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"58\">‘fixed action pattern’</strong>… It is not a reflex…” (Đoạn 4).</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc phân biệt ngáp không phải là phản xạ (reflex) mà là một <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"76\">mô hình hành động cố định (fixed action pattern)</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. Provine found that a typical yawn lasts about {J: 6 seconds}.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The standard yawn runs its course over about <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"57\">six seconds</strong> on average…” (Đoạn 4).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. …yawn a number of times in quick succession with the yawns usually being around {E: 68 seconds} apart.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…which is generally about <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"40\">68 seconds</strong> but rarely more than 70.” (Đoạn 4).</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các cơn ngáp thường đến theo đợt và cách nhau khoảng 68 giây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. …people who yawn less do not necessarily produce {B: long yawns} to make up for this.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “There is no relation between yawn frequency and duration: producers of short or long yawns <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"103\">do not compensate</strong> by yawning more or less often.” (Đoạn 4).</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người ngáp ít không nhất thiết phải ngáp những cái <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"63\">ngáp dài (long yawns)</strong> để bù đắp (make up for/compensate).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('92402ef4-b4e1-4aea-ad1c-d3578eea0d40', 'b6e85a44-1d42-41ad-bfb5-f1cba09022cd', 'radio', 'Questions 36-40', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C</strong>, or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. To define international tourism"}, {"option_text": "B. To praise the economic potential of tourism"}, {"option_text": "C. To introduce the complex and contradictory nature of tourism"}, {"option_text": "D. To criticize the growth of the tourism sector"}], "question": "What is the writer''s main purpose in the first paragraph?"}, {"correct": 1, "options": [{"option_text": "A. To preserve cultural traditions accurately"}, {"option_text": "B. To meet the expectations of investors and tourists"}, {"option_text": "C. To make them easier for locals to perform"}, {"option_text": "D. To protect them from outside influence"}], "question": "According to the passage, why do tourist destinations often standardize their cultural presentations?"}, {"correct": 1, "options": [{"option_text": "A. How tourism helps preserve natural environments."}, {"option_text": "B. The need for tourism to make cultural and natural phenomena static and defined."}, {"option_text": "C. The diversity of attractions available to tourists."}, {"option_text": "D. The negative environmental impact of tourism."}], "question": "The writer uses the example of \"folk dances\" and \"the course of the Amazon\" to illustrate:"}, {"correct": 1, "options": [{"option_text": "A. Tourism helps cultures evolve in a healthy way."}, {"option_text": "B. Tourism tends to simplify and commercialize culture."}, {"option_text": "C. Tourism has no significant impact on deep cultural values."}, {"option_text": "D. Tourism is the best way to fund cultural preservation."}], "question": "What does the writer imply about the relationship between tourism and culture?"}, {"correct": 3, "options": [{"option_text": "A. Tourism''s benefits far outweigh its costs."}, {"option_text": "B. Tourism is a simple and positive force for development."}, {"option_text": "C. The effects of tourism are straightforward and easy to manage."}, {"option_text": "D. Tourism involves fundamental tensions that must be carefully managed."}], "question": "What is the overall message of the passage?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. C. To introduce the complex and contradictory nature of tourism</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“International tourism presents itself as straightforward... <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"81\">yet it is complex, interesting and important, full of contradictions and depths</strong>. Yet whether and how to grow is <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"193\">not nearly as straightforward</strong> as one might hope.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngay từ đoạn mở đầu, tác giả đã dùng các từ tương phản (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"68\">yet, not nearly as straightforward</em>) để khẳng định rằng du lịch quốc tế không hề đơn giản mà ngược lại, nó rất phức tạp (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"188\">complex</strong>) và chứa đầy những nghịch lý (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"226\">full of contradictions</strong>). Đây chính là mục đích cốt lõi nhằm giới thiệu bản chất của toàn bài viết.</p>\n<ul data-path-to-node=\"5,1,1\">\n<li>\n<p data-path-to-node=\"5,1,1,0,0\"><em data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Loại A:</em> Đoạn này không đưa ra định nghĩa học thuật về du lịch.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,1,1,0\"><em data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Loại B &amp; D:</em> Đoạn này có nhắc đến tiềm năng kinh tế và sự mở rộng nhưng mục đích không phải để ca ngợi (<em data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"103\">praise</em>) hay chỉ trích (<em data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"126\">criticize</em>) mà là để chỉ ra sự mâu thuẫn.</p>\n</li>\n</ul>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. B. To meet the expectations of investors and tourists</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“As a consequence, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"39\">investors tend to look for the familiar</strong> in foreign places. This affects tourism in two key ways: <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"136\">destinations may standardize their offerings to suit perceived tourist tastes</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ ra hai nguyên nhân khiến các điểm đến phải chuẩn hóa sản phẩm: một là do các nhà đầu tư luôn tìm kiếm sự quen thuộc (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"141\">investors look for the familiar</em>), hai là để phù hợp với thị hiếu/sở thích của khách du lịch (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"234\">suit perceived tourist tastes</em>). Hai ý này gộp lại chính là đáp ứng kỳ vọng của cả nhà đầu tư và du khách (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"340\">meet the expectations of investors and tourists</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. B. The need for tourism to make cultural and natural phenomena static and defined.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“As a consequence, <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"39\">efforts are made to crystallize and standardize: folk dances</strong>... and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"107\">the course of the Amazon have all been bound and defined. Had they not been fixed, however, they would not be accessible</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra các ví dụ về điệu múa dân gian hay dòng chảy sông Amazon để chứng minh rằng ngành du lịch luôn tìm cách đóng khung, định hình (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"154\">crystallize, standardize, bound, defined</em>) và cố định chúng (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"214\">fixed/static</em>). Nếu không làm cho chúng bất biến và rõ ràng như vậy, du khách sẽ không thể tiếp cận được.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. B. Tourism tends to simplify and commercialize culture.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5 &amp; 7):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"24\">“...tourism <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"36\">favors what can be commodified</strong> [commercialized]... It values tradition but <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"111\">freezes it into a marketable form</strong> [simplify].”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả ngầm ý và đúc kết rằng mối quan hệ giữa du lịch và văn hóa là mối quan hệ thương mại hóa. Du lịch chỉ ưu tiên những gì có thể biến thành hàng hóa bán được (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"176\">commodified / marketable form</em>) và có xu hướng đóng băng, đơn giản hóa các nét văn hóa sâu sắc để phục vụ mục đích kinh doanh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. D. Tourism involves fundamental tensions that must be carefully managed.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Ultimately, <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"33\">tourism is a paradoxical force</strong>... Understanding these <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"87\">contradictions is essential for managing tourism’s impacts</strong> in a way that <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"160\">balances economic gain with the preservation of cultural and environmental integrity</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn kết luận, tác giả chốt lại thông điệp tổng thể của toàn bài: Du lịch là một thế lực đầy nghịch lý và mâu thuẫn (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"131\">paradoxical force / contradictions</em>), tạo ra những xung đột nội tại (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"199\">fundamental tensions</strong>). Do đó, việc thấu hiểu chúng là vô cùng thiết yếu để có thể quản lý các tác động một cách cẩn trọng (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"322\">carefully managed</strong>), giúp cân bằng giữa kinh tế và bảo tồn văn hóa.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('9b2b803f-722e-469e-93c3-66dbacd84079', '63ec898c-bed9-4489-bb40-eef5c5529c79', 'matrix', 'Questions 27–31', NULL, '<p>Reading Passage 3 has six sections, A-F.</p>
<p>Which section contains the following information?</p>
<p><em><strong>NB </strong>You may use any letter more than once</em></p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "Detailed criticism of the methodology of a project", "correctCategoryLetter": "D"}, {"itemText": "A comparison of the data from class-reduction projects", "correctCategoryLetter": "F"}, {"itemText": "The level of public interest in the issues of class-size reduction", "correctCategoryLetter": "A"}, {"itemText": "Details of action taken to protect the validity of a project", "correctCategoryLetter": "C"}, {"itemText": "Reasons why class composition changed during a project", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p><strong>27. detailed criticism of the methodology of a project</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) Eric Hanushek <strong>“criticises some of STAR’s key conclusions”</strong> và nêu chi tiết các lỗi trong phương pháp luận (methodology): <strong>“does not prove that gains persist long after students return to regular classes”</strong>, <strong>“failed to ensure good randomisation of teacher and student assignments”</strong>.</li>\n</ul>\n<p><strong>28. a comparison of the data from class-reduction projects</strong></p>\n<ul>\n<li><strong>Đáp án: F</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Analysts have studied the results of first-grade students in these schools and similar first-grade students elsewhere and found the results <strong>accord with those from STAR</strong>.”</li>\n<li><strong>Giải thích:</strong> Đoạn F so sánh kết quả của dự án SAGE với dự án STAR.</li>\n</ul>\n<p><strong>29. the level of public interest in the issues of class-size reduction</strong></p>\n<ul>\n<li><strong>Đáp án: A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “With its uncomplicated appeal, class-size reduction in the U.S. has lately gone from being a subject of primary academic interest to a <strong>policy juggernaut</strong> with over twenty states aiming at decreasing class sizes.”</li>\n<li><strong>Giải thích:</strong> Việc trở thành một “policy juggernaut” và được hơn 20 tiểu bang theo đuổi cho thấy mức độ quan tâm và ủng hộ cao của công chúng và chính phủ.</li>\n</ul>\n<p><strong>30. details of action taken to protect the validity of a project</strong></p>\n<ul>\n<li><strong>Đáp án: C</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “<strong>To ensure that teaching quality did not differ, teachers were randomly assigned to small and regular-size classrooms.</strong>“</li>\n<li><strong>Giải thích:</strong> Việc sắp xếp giáo viên ngẫu nhiên là hành động nhằm bảo vệ tính hợp lệ (validity) của nghiên cứu.</li>\n</ul>\n<p><strong>31. reasons why class composition changed during a project</strong></p>\n<ul>\n<li><strong>Đáp án: D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “…too many children moved from regular to small classes, <strong>probably because school personnel caved in to parent demands</strong>.”</li>\n<li><strong>Giải thích:</strong> Nhu cầu từ phụ huynh khiến thành phần lớp học bị thay đổi trong dự án STAR.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('82286d10-2117-4045-b833-b29c285d78bf', '241ff6c4-b920-44a6-93be-c58d32c2d576', 'radio', 'Questions 8–13', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information  <strong>FALSE </strong>if the statement contradicts the information  <strong>NOT GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The ice transportation business made some Boston ship owners very wealthy in the early 1800s."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "A disadvantage of the freezing process invented in Australia was that it affected the taste of food."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Clarence Birdseye travelled to Labrador in order to learn how the Inuit people froze fish."}, {"correct": 0, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Swanson Foods invested a great deal of money in the promotion of the TV Dinner."}, {"correct": 1, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "Swanson Foods developed a new style of container for the launch of the TV Dinner."}, {"correct": 2, "options": [{"content": "TRUE "}, {"content": "FALSE "}, {"content": "NOT GIVEN"}], "question": "The US frozen food industry is currently the largest in the world."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>8. NOT GIVEN<br />→ Không có thông tin về việc chủ tàu ở Boston trở nên giàu có nhờ vận chuyển băng. → NOT GIVEN.</p>\n<p> <br />9. TRUE<br />(Đoạn 4: “While the food frozen this way was still palatable, there was some deterioration… this spoilt the flavor and texture.”)<br />→ Phương pháp đông lạnh ở Úc có ảnh hưởng đến hương vị → TRUE.</p>\n<p> <br />10. FALSE<br />(Đoạn 5: “He went to Labrador… to trap and trade furs… While he was there, he became fascinated with how the Inuit would quickly freeze fish.”)<br />→ Birdseye không đến để học cách người Inuit bắt cá, mà do đi buôn da thú và tình cờ phát hiện ra → FALSE.</p>\n<p> <br />11. TRUE<br />(Đoạn 9: “With the help of a clever name and a huge advertising budget, it launched the first ‘TV Dinner’. The product was an instant success.”)<br />→ Swanson đầu tư mạnh tay cho quảng bá món TV Dinner → TRUE.</p>\n<p> <br />12. FALSE<br />(Đoạn 9: “They launched the first ‘TV Dinner’… served in the same segmented aluminum tray that was used by airlines.”)<br />→ Swanson không phát triển khay mới, mà dùng lại loại khay của hàng không → FALSE.</p>\n<p> <br />13. NOT GIVEN<br />→ Bài không đề cập ngành thực phẩm đông lạnh lớn nhất thế giới là Mỹ. → NOT GIVEN.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('0b83a842-b98d-40cf-966f-2d44df5b234a', 'd3b634d8-6012-4da2-a451-41468faf1231', 'radio', 'Questions 11–14', NULL, '<p>Choose the correct answer.</p>
<p style="text-align: left;"><strong>The McFaddin hiking and nature trail</strong></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "provide secure parking facilities from cars."}, {"content": "are within easy access from public roads."}, {"content": "have a regular shuttle bus service."}], "question": "All entry points along the trail"}, {"correct": 2, "options": [{"content": "electric recharge points"}, {"content": "picnic areas"}, {"content": "maps and other information"}], "question": "Which facilities at the trail rest stations has been added as a result of a user survey?"}, {"correct": 0, "options": [{"content": "see many different plants."}, {"content": "enjoy spectacular scenic views."}, {"content": "identify a wide range of birds."}], "question": "On the Red Rock Walk, hikers are easily able to"}, {"correct": 2, "options": [{"content": "There are not many other walkers in the area."}, {"content": "The area does not get much ice and snow."}, {"content": "It may not be possible to use this section of the trail."}], "question": "What does the speaker say about the River Walk in wintertime?"}]', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Susan Meyer:</strong> Good morning. I’m Susan Meyer, trail warden for the McFadden Hiking and Nature Trail. Let me tell you a bit about the trail. The trail is 25 miles long, running roughly east to west. To hike it, you may start at either end of the trail or in between. You can hike the whole length of the trail or just a couple of miles, because <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"3\" data-index-in-node=\"342\">(11) there are 20 entry points along the trail, each connected to public roads by short paths (B)</strong></span>.</p>\n<p data-path-to-node=\"4\">For hikers coming from Johnson City, there’s a shuttle bus to each of the two end points every morning and evening, and four of the entry points have a free car park with television camera surveillance. At 1 mile intervals along the trail, there are rest stations providing picnic areas, water, toilets, and places where you can recharge your electronic devices. In response to a poll of walkers last year, we’ve <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"4\" data-index-in-node=\"413\">(12) recently installed kiosks at each rest station with clear, easy to follow maps and other trail information (C)</strong></span>.</p>\n<p data-path-to-node=\"5\">There are several distinct sections of trail. The Red Rock Walk offers a superb opportunity to <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"5\" data-index-in-node=\"95\">(13) study a huge variety of vegetation along the way (A: see many different plants)</strong>.</span> There’s lots to look at, though you can’t see great distances. Birds are actually hard to spot, but with a pair of binoculars and at certain times of day, you may see some rare varieties.</p>\n<p data-path-to-node=\"6\">The River Walk comprises about 5 miles of trail, winding along the bank of the Moultrie River. Personally, I prefer this section of the trail in winter. The river does freeze over and the snow can accumulate, but that doesn’t always discourage visitors. Sometimes though, <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"6\" data-index-in-node=\"272\">(14) if the weather conditions are really unsuitable, we might have to close this walk to the public (C: It may not be possible to use this section)</strong></span>, but often it can get crowded with hikers who’ve discovered the attraction of the area.</p>\n<hr data-path-to-node=\"7\" />\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Susan Meyer:</strong> Now let me tell you about the Halfway Hostel, located approximately midway along the trail. It has a range of facilities available to help make your walking experience memorable. Let me give you some information about the various facilities available there.</p>\n<p data-path-to-node=\"9\">Of course, there are beds in dormitories for use at a very reasonable $7 per person, weekdays or weekends. Unfortunately, we found that pre-booking beds just didn’t work, so <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"9\" data-index-in-node=\"174\">(15) now we allocate them as people arrive (H: first-come-first-served basis)</strong></span>, but we have extra cots and sleeping bags to help with any overflow.</p>\n<p data-path-to-node=\"10\">There are two family rooms accommodating six people, each with private bathrooms. They are $35 per room and for them, <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"10\" data-index-in-node=\"118\">(16) you will need to make arrangements ahead of time (F: advance booking required)</strong></span> as they’re very popular, especially at the weekends.</p>\n<p data-path-to-node=\"11\">A popular facility that <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"11\" data-index-in-node=\"24\">(17) we’ve recently added is coin-operated washing machines (G: new equipment)</strong></span> for your clothes. You can get awfully wet and dirty if you’re walking the trail in bad weather, and since we got these machines, you can put on clean gear when you set out in the morning.</p>\n<p data-path-to-node=\"12\">The hostel serves two meals a day—breakfast at $4 and dinner at $8, the same for adults and kids. There’s always a vegetarian and a non-vegetarian option, depending on your preferences. <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"12\" data-index-in-node=\"186\">(18) We do ask you to give a hand with serving and cleaning up after meals (D: help from guests requested)</strong></span>.</p>\n<p data-path-to-node=\"13\">We have plenty of showers and unlimited hot water available, so <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"13\" data-index-in-node=\"64\">(19) you can have this luxury at no charge (E: provided free)</strong></span>, and you can enjoy it as long as you like.</p>\n<p data-path-to-node=\"14\">Now, some people like to spend time on the trail on mountain bikes, and maybe take a bit of a rest from all that walking, and that’s permitted as long as you observe basic safety rules. The hostel’s <span style=\"text-decoration: underline; background-color: #fbeeb8;\"><strong data-path-to-node=\"14\" data-index-in-node=\"199\">(20) in the process of creating a bike rental scheme, which should be up and running next year (C: not yet available)</strong></span>. So if you think that…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('e4eb00a9-d57f-432b-a4f2-b39a0c246f20', 'c0760ea7-11fa-4c27-ab40-cb7bc18a3546', 'radio', 'Questions 33-37', NULL, '<p>Choose the correct letter, A, B, C or D.</p>', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "A Ending a yawn requires use of the nostrils."}, {"content": "B You can yawn without breathing through your nose"}, {"content": "C Breathing through the nose produces a silent yawn."}, {"content": "D The role of the nose in yawning needs further investigation."}], "question": "What did Provine conclude from his ‘closed nose yawn’ experiment?"}, {"correct": 2, "options": [{"content": "A yawning is unconnected with fatigue."}, {"content": "B a yawn is the equivalent of a deep intake of breath."}, {"content": "C you have to be able to open your mouth wide to yawn."}, {"content": "D breathing with the teeth together is as efficient as through the nose."}], "question": "Provine''s clenched teeth yawn''s experiment shows that"}, {"correct": 3, "options": [{"content": "A can be stopped after it has stated"}, {"content": "B is the result of motor programing"}, {"content": "C involves both inhalation and exhalation"}, {"content": "D can be accomplished only through the nose."}], "question": "The nose yawn experiment was used to test whether yawning"}, {"correct": 2, "options": [{"content": "A yawning may involve only one side of the face."}, {"content": "B the yawing response indicates that recovery is likely"}, {"content": "C movement in a paralyzed arm is stimulated by yawning"}, {"content": "D yawning can be used as an example to prevent muscle wasting."}], "question": "In people paralyzed on one side because of brain damage"}, {"correct": 1, "options": [{"content": "A yawning is a sign of boredom."}, {"content": "B we yawn is spite of the development of our species"}, {"content": "C yawning is a more passive activity than we imagine"}, {"content": "D we are stimulated to yawn when our brain activity is low"}], "question": "In the last paragraph, the writer concludes that"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">33. What did Provine conclude from his ‘closed nose yawn’ experiment?</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong class=\"\" data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> You can yawn without breathing through your nose.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"16\">i) The closed nose yawn</strong><span class=\"\">:</span><span class=\"\"> “This indicates that the inhalation…</span><span class=\"\"> and the exhalation…</span><span class=\"\"> need not involve the nostrils – the mouth provides a sufficient airway.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong class=\"\" data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Khi bịt mũi,</span><span class=\"\"> người tham gia vẫn ngáp bình thường được vì miệng đã cung cấp đủ đường thở.</span><span class=\"\"> Điều này chứng minh mũi không đóng vai trò bắt buộc trong cơ chế của cơn ngáp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">34. Provine’s clenched teeth yawn experiment shows that</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> You have to be able to open your mouth wide to yawn.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"16\">ii) The clenched teeth yawn</strong><span class=\"\">:</span><span class=\"\"> “This shows that gaping of the jaws is an essential component…</span><span class=\"\"> and unless it is accomplished,</span><span class=\"\"> the program will not run to completion.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong class=\"\" data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Việc cắn chặt răng khiến người ta cảm thấy bị “kẹt” giữa chừng.</span><span class=\"\"> Do đó,</span><span class=\"\"> việc há rộng hàm (gaping of the jaws) là điều kiện cần để hoàn thành một cơn ngáp trọn vẹn.</span></p>\n<p class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">35. The nose yawn experiment was used to test whether yawning</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án của bạn:</strong><span class=\"\"> Is the result of motor programming.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><strong class=\"\" data-path-to-node=\"6,2,0\" data-index-in-node=\"16\">iii) The nose yawn</strong><span class=\"\">:</span><span class=\"\"> “The motor program for yawning will not run to completion without feedback that these parts of the program [inhalation through oral airway and gaping of jaws] have been accomplished.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,3,0\"><strong class=\"\" data-path-to-node=\"6,3,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thí nghiệm này cho thấy não bộ có một “chương trình vận động” (motor program) cài sẵn.</span><span class=\"\"> Nếu chỉ hít vào bằng mũi mà không qua miệng,</span><span class=\"\"> não không nhận được tín hiệu phản hồi rằng “các bước đã hoàn thành”,</span><span class=\"\"> dẫn đến việc cơn ngáp không thể kết thúc.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">36. In people paralyzed on one side because of brain damage</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong><span class=\"\"> Movement in paralysed arm is stimulated by yawning.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn gần cuối:</span><span class=\"\"> “…</span><span class=\"\">when these people yawn,</span><span class=\"\"> they are startled…</span><span class=\"\"> to observe that their otherwise paralyzed arm rises and flexes automatically in what neurologists term an ‘associated response’.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong class=\"\" data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Khi ngáp,</span><span class=\"\"> các kết nối vô thức giữa não và hệ vận động (không bị tổn thương bởi đột quỵ) được kích hoạt,</span><span class=\"\"> khiến cánh tay bị liệt tự động cử động mà người bệnh không tự điều khiển được.</span></p>\n<p class=\"attachment-container search-images\"><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">37. </strong><strong data-path-to-node=\"11\" data-index-in-node=\"0\">In the last paragraph, the writer concludes that </strong></p>\n<ul>\n<li data-path-to-node=\"9\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Đáp án: {B. we yawn is spite of the development of our species}</strong></li>\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn cuối):</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"23\">“Yawning is also a reminder that <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"56\">ancient and unconscious behavior</strong> linking US to the animal world <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"120\">lurks beneath the veneer of culture, rationality and language</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả kết luận rằng ngáp là một hành vi cổ xưa và vô thức, nó vẫn tồn tại bên dưới lớp vỏ bọc văn minh, lý trí và ngôn ngữ của con người hiện đại.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('b284df26-382b-4b0d-ae1a-f3bfe34a9363', 'd3b634d8-6012-4da2-a451-41468faf1231', 'matching', 'Questions 15–20', NULL, '<p>Which information is given about each of the following facilities at the Halfway Hostel?</p>
<p>Choose <strong>SIX </strong>correct answers, <strong>A-I</strong>, next to questions <strong>15-20</strong>.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Facilities at the hostel</strong></p>\n<p> </p>\n<p>dormitory beds {H available on first-come-first-served basis}</p>\n<p> </p>\n<p>family rooms {F advance booking required}</p>\n<p> </p>\n<p>clothes washing {G new equipment}</p>\n<p> </p>\n<p>meals {D help from guests requested}</p>\n<p> </p>\n<p>hot showers {E provided free}</p>\n<p> </p>\n<p>bicycle rental {C not yet available}</p>", "answerOptions": [{"optionText": "A only at weekends"}, {"optionText": "B voluntary donation expected"}, {"optionText": "C not yet available"}, {"optionText": "D help from guests requested"}, {"optionText": "E provided free"}, {"optionText": "F advance booking required"}, {"optionText": "G new equipment"}, {"optionText": "H available on first-come-first-served basis"}, {"optionText": "I special rate for children"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('1a8e7978-23b5-4b3f-b0cb-984c3cf0e5bc', 'c0760ea7-11fa-4c27-ab40-cb7bc18a3546', 'radio', 'Question 38-40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the claims of the writer, choose <strong>NO </strong>if the statement contradicts the claims of the writer, or <strong>NOT GIVEN</strong> if it is impossible to say what the writer thinks about this.</p>', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Research students were initially reluctant to appreciate the value of Provine''s studies."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "When foetuses yawn and stretch they are learning how to control movement"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "According to Provine, referring to only one function is probably inadequate to explain why people yawn."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">38. Research students were initially reluctant to appreciate the value of Provine’s studies. — {YES}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"16,0,0\" data-index-in-node=\"20\">“When Robert R Provine began studying yawning… it was <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"76\">difficult for him to convince research students of the merits of ‘yawning science’</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc Provine gặp khó khăn trong việc thuyết phục sinh viên về giá trị của môn học này đồng nghĩa với việc ban đầu họ còn miễn cưỡng (reluctant) và chưa đánh giá cao nó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">39. When foetuses yawn and stretch they are learning how to control movement — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn gần cuối):</strong> <em data-path-to-node=\"18,0,0\" data-index-in-node=\"27\">“Studies… charting movement in the developing foet US using ultrasound, observed a <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"112\">link between yawning and stretching</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập đến việc quan sát thấy mối liên hệ giữa ngáp và duỗi người ở bào thai, nhưng <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"108\">không có thông tin</strong> nào nói rằng chúng đang “học cách kiểm soát cử động” (learning how to control movement).</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">40. According to Provine, referring to only one function is probably inadequate to explain why people yawn. — {YES}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn cuối):</strong> <em data-path-to-node=\"20,0,0\" data-index-in-node=\"23\">“Provine speculated that… yawning may have <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"68\">many functions</strong>, and selecting a <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"100\">single function</strong> from the available options may be an <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"153\">unrealistic goal</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Provine tin rằng ngáp có nhiều chức năng, nên việc chỉ chọn ra một chức năng duy nhất để giải thích là điều không thực tế (inadequate/unrealistic).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('2e370b27-d817-479a-917c-982b93deed3e', '83ae0844-3dd2-44ee-afc5-6a45d730600d', 'radio', 'Questions 33–35', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "A They meticulously plan each phase of their movements."}, {"content": "B They engage in regular practice to retain and refine their skills"}, {"content": "C They actively consider and analyse the actions of their peers"}, {"content": "D They perform their actions without conscious contemplation"}], "question": "What point does the writer make about professional athletes in Paragraph B?"}, {"correct": 0, "options": [{"content": "A the critical role of imitation in the formation of consciousness"}, {"content": "B the improvement of sporting ability through watching sport."}, {"content": "C the stimulation of a resonance in the observer''s motor system"}, {"content": "D the motivation of the observer''s interest and love for golf."}], "question": "In this passage, the writer mentions the example of a remarkable golfer to illustrate"}, {"correct": 0, "options": [{"content": "A to improve our physical ability by analyzing the athletes’ technical strategies"}, {"content": "B to unite viewers from different nations"}, {"content": "C to experience intense positive emotions by immersing oneself in sport"}, {"content": "D to become a sports professional."}], "question": "The principal motivation for watching sport mentioned by the writer is"}]', 'null', 'null', 'null', '[{"content": "<p><strong>33. What point does the writer make about professional athletes in Paragraph B?</strong></p>\n<ul>\n<li><strong>Đáp án: D. They perform their actions without conscious contemplation.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “Experts, by contrast, instinctively execute perfectly balanced movements… Their swing occurs with the serenity of a refined autopilot, <strong>requiring no conscious control</strong>.”</li>\n</ul>\n<p><strong>34. In this passage, the writer mentions the example of a remarkable golfer to illustrate</strong></p>\n<ul>\n<li><strong>Đáp án: B. the improvement of sporting ability through watching sport.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “It turns out that <strong>watching a remarkable golfer improves our own golfing skills</strong>, and witnessing a skilled sprinter actually bolsters our running speed.”</li>\n</ul>\n<p><strong>35. the principal motivation for watching sport mentioned by the writer is</strong></p>\n<ul>\n<li><strong>Đáp án: C. to experience intense positive emotions by immersing oneself in sport.</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Most spectators tune in for the <strong>emotional roller coaster</strong>… which allow spectators to perceive athletes’ victorious movements and to <strong>share in the emotion of their triumphs</strong>.”</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('4202a3f7-c4bc-4b2b-a36f-190b29c5037a', '346fd6f7-7513-41f5-9370-889ecca9aab9', 'checkbox', 'Questions 19-20', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>19-20 Joan says the <strong>TWO </strong>ways the RDA needs to improve are by</p>
', 'multiple_choice_many', 'null', '[{"option": "A. giving special training.", "correct": false}, {"option": "B. making fund-raising more effective.", "correct": true}, {"option": "C. opening more RDA centres.", "correct": false}, {"option": "D. providing more helpers.", "correct": false}, {"option": "E. recognising difficulties of disabled riders", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 3);
INSERT INTO public.questions VALUES ('b2841ea4-3756-41c6-926c-f71520ddc113', '52863fe0-c78e-400f-9ba9-dc97b09c536c', 'fillup', 'Questions 22-27', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.<br />
Write your answers in boxes <strong>22-27</strong></div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p style="text-align: center;"><span style="font-size: 12pt;"><strong>Aestivation</strong></span></p>
<p>In many places inhabited by crocodilians, most types of crocodiles have evolved a successful scheme to survive in the drought brought by a {hot season|dry season} According to Kennett and Christian’s six-year study of Australian freshwater crocodiles’ aestivation, they found estivating crocodiles spent around {four months} of the year and had no access to {water resources} The amount of water in the body declined proportionately with {body weight}; thus there is no sign of {dehydration} and other health-damaging impact on the crocodiles even after an aestivation period. This super capacity helps crocodiles endure the tough drought without slowing their speed of {growth}</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-heading"></div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">22. hot season / dry season</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> * Đoạn E, câu 1: <em data-path-to-node=\"3,0,0\" data-index-in-node=\"28\">“In many crocodilian habitats, the <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"63\">hot season</strong> brings drought…”</em></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\">Đoạn F, câu 1: <em data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"15\">“…go into aestivation during the <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"50\">dry season</strong>.”</em></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cả hai cụm từ này đều chỉ thời điểm hạn hán xảy ra khiến cá sấu phải ngủ hè. Bạn có thể dùng một trong hai cụm từ này (đều gồm 2 từ, thỏa mãn yêu cầu đề bài).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">23. four months</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn F, câu 2: <em data-path-to-node=\"6,0,0\" data-index-in-node=\"26\">“In a six-year study… spent nearly <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"63\">four months</strong> a year underground…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nghiên cứu của Kennett và Christian chỉ ra rằng loài cá sấu nước ngọt ở Úc dành khoảng <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"99\">4 tháng</strong> mỗi năm để ngủ hè dưới lòng đất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">24. water resources</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn F, câu 2: <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“…spent nearly four months a year underground without access to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"92\">water resources</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong suốt thời gian ngủ hè dưới lòng đất, cá sấu hoàn toàn không tiếp cận được với các <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"100\">nguồn nước</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">25. body weight</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn G, câu 4: <em data-path-to-node=\"12,0,0\" data-index-in-node=\"26\">“…even though the crocodiles lost water reserves and <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"81\">body weight</strong> when underground, the losses were proportional…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Lượng nước trong cơ thể giảm đi một cách tương ứng (proportional) với <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"82\">trọng lượng cơ thể</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. dehydration</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn G, câu 5: <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“…upon emerging, the aestivating animals had no <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"76\">dehydration</strong> and displayed no other harmful effects…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì sự sụt giảm nước và trọng lượng là tương đương nên sau khi thức dậy, cá sấu không có dấu hiệu bị <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"112\">mất nước</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">27. growth </strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn G, câu cuối: <em data-path-to-node=\"18,0,0\" data-index-in-node=\"29\">“…and displayed no other harmful effects such as a slowed-down <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"94\">growth </strong>rate.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khả năng siêu việt này giúp cá sấu vượt qua hạn hán mà không làm chậm tốc độ <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"89\">tăng trưởng</strong> (growth) của chúng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('fae0d545-7d2f-44d1-8afa-ad0de03eae62', 'ca19f140-6fc3-4bb7-b56e-c264302b0b2c', 'radio', 'Questions 32-35', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Although Oscar Wilde admired Robert Louis Stevenson very much, he believed Stevenson could have written greater works."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Robert Louis Stevenson encouraged Oscar Wilde to start writing at first."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Galsworthy thought Hardy is greater writer than Stevenson is."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Critics only paid attention to Robert Louis Stevenson’s writing topics."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">32. Although Oscar Wilde admired Robert Louis Stevenson very much, he believed Stevenson could have written better works if he wasn’t born in Scotland.</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 7–9.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Though Stevenson’s works have deeply influenced Oscar Wilde, Wilde often joked that Stevenson <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"106\">would have written better works if he wasn’t born in Scotland</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận Oscar Wilde chịu ảnh hưởng sâu sắc bởi Stevenson (thể hiện sự ngưỡng mộ) nhưng ông cũng đùa rằng Stevenson sẽ viết tốt hơn nếu không sinh ra ở Scotland. Nội dung này khớp hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">33. Robert Louis Stevenson encouraged Oscar Wilde to start writing at first.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Though Stevenson’s works have deeply influenced Oscar Wilde…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói rằng các tác phẩm của Stevenson đã <strong data-path-to-node=\"5,3,0\" data-index-in-node=\"63\">ảnh hưởng sâu sắc</strong> đến Oscar Wilde. Tuy nhiên, không có thông tin nào đề cập đến việc Stevenson trực tiếp <strong data-path-to-node=\"5,3,0\" data-index-in-node=\"168\">khuyến khích</strong> (encouraged) Wilde bắt đầu sự nghiệp cầm bút.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">34. Galsworthy thought Hardy is a greater writer than Stevenson.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Other authors came to Stevenson’s defence, including Galsworthy who claimed that <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"93\">Stevenson is a greater writer than Thomas Hardy</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định Galsworthy cho rằng Stevenson là nhà văn vĩ đại hơn Thomas Hardy. Câu hỏi nói ngược lại (Hardy vĩ đại hơn Stevenson), do đó đáp án là False.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">35. Critics only paid attention to Robert Louis Stevenson’s writing topics.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…his writing was <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"31\">not the only source of attention</strong> for critics. Stevenson’s <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"89\">personal life</strong> often attracted a lot of attention from his fans and critics alike.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,3,0\"><strong data-path-to-node=\"9,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ rõ rằng các chủ đề viết lách (writing topics) <strong data-path-to-node=\"9,3,0\" data-index-in-node=\"70\">không phải là nguồn chú ý duy nhất</strong>. Các nhà phê bình còn đặc biệt quan tâm đến <strong data-path-to-node=\"9,3,0\" data-index-in-node=\"149\">đời tư</strong> (personal life) và lối sống phiêu lưu của ông. Từ “only” trong câu hỏi làm cho khẳng định này trở nên sai so với bài đọc.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('f2e96dee-4eb8-49c4-8a1a-02d28ad055bc', '3c753462-8c7a-41a6-b84a-926c7b5b4782', 'radio', 'Questions 11–16', NULL, '<p>Choose the correct answer.</p>
', 'multiple-choice', '[{"correct": 0, "options": [{"content": "the general operation of the camp"}, {"content": "the children who attend"}, {"content": "the job responsibilities"}], "question": "The speaker says that he is happy to answer questions during his talk about"}, {"correct": 2, "options": [{"content": "They like the fact that it is cheaper than other camps."}, {"content": "They are pleased with the wide range of facilities on offer."}, {"content": "They know their children will be looked after at the camp."}], "question": "Why do parents send their children to the camp again and again?"}, {"correct": 1, "options": [{"content": "the number of international students"}, {"content": "the preparation for professional sports"}, {"content": "the inclusion of non-sports activities"}], "question": "One special thing about this summer camp is"}, {"correct": 2, "options": [{"content": "who would like to work in the ofﬁce"}, {"content": "who have experience of cooking"}, {"content": "who young children can talk to"}], "question": "The speaker says that this year, the camp particularly needs people"}, {"correct": 0, "options": [{"content": "artistic talents"}, {"content": "good camera equipment"}, {"content": "a qualiﬁcation in photography"}], "question": "What should the new cameraperson have?"}, {"correct": 0, "options": [{"content": "Sports coaches earn the most."}, {"content": "Kitchen staff work the longest hours."}, {"content": "Cleaners work in the mornings and evenings."}], "question": "What does the speaker say about working conditions?"}]', 'null', 'null', 'null', '[{"content": "<h2 data-path-to-node=\"2\">PART 2</h2>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Speaker:</strong> Welcome to this talk about the UK Summer Sports Camp. I’m going to tell you about our summer sports camp for children and something about the children who come. Later on, I’ll tell you how to apply if you’d like to work with us this year. So please be patient.</p>\n<p data-path-to-node=\"4\">Feel free to interrupt if there’s anything you don’t understand about the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"74\">(11) way the camp is administered (A: general operation)</strong></span>, though if you could save any questions about the work itself until the end, that would be good.</p>\n<p data-path-to-node=\"5\">The UK Summer Sports Camp offers courses for kids aged six to 16, which focus on a wide range of sports and activities. Our aim is to provide a fun, safe experience for kids. The reason we’re successful is because <span style=\"background-color: #ffffff;\"><span data-path-to-node=\"5\" data-index-in-node=\"214\">parents trust us and send their children to us summer after summer</span>.</span> <span style=\"background-color: #fae077;\"><strong><u>(12) </u></strong><u><strong><span style=\"background-color: #fae077;\">We </span>aren’t the cheapest camp around, which might put some people off, but we make sure our team are caring and enthusiastic, and that’s why parents want their children to keep coming back, rather than because of the facilities on offer, great as they are, of course</strong></u></span>.</p>\n<p data-path-to-node=\"6\">We think our summer camp is special in a number of ways. We have students from all over the country, not just the local area. We run all the activities you’d expect in a summer camp—arts and music as well as sports—but we also have <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"232\">(13) special coaching for those who might be able to make a career in their chosen sport (B: preparation for professional sports)</strong>.</span></p>\n<p data-path-to-node=\"7\">What will your role be if you come and work with us then? We need lots of people who are willing to teach the activities, but we also have non-coaching roles. What we particularly like this summer are <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"7\" data-index-in-node=\"201\">(14) people who are willing to be in charge of looking after our younger kids, making sure they’re happy and have someone to go to if they have any problems (C: young children can talk to)</strong></span>. We usually need a few cooks too, though we don’t need anyone extra for our office at the moment.</p>\n<p data-path-to-node=\"8\">This year, I’m very pleased to introduce a new role at the camp: camera person. We need someone with great video and photography skills to record the fun everyone has. We’ll supply first-class equipment, but we <strong data-path-to-node=\"8\" data-index-in-node=\"211\">(<span style=\"text-decoration: underline; background-color: #ffe786;\">15) need you to supply your creative abilities (A: artistic talents)</span></strong>. If you’re interested in this role, come and talk to me at the end.</p>\n<p data-path-to-node=\"9\">Now you probably want to know about working conditions, hours and pay. This depends on your role. You can choose to work daytimes, evenings or weekends. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"153\">(16) Daytime coaching roles pay the highest wages (A: sports coaches earn the most)</strong> </span>because of the sports skills required and the longer hours. If you choose to work in the kitchen, your hours of work will be either at breakfast and lunch or at dinner. Cleaners work in the mornings before the camp activities start at 10:00 am, so not too early.</p>\n<hr data-path-to-node=\"10\">\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Speaker:</strong> If you do work with us, there are lots of benefits in addition to the money. Whether you’re teaching a sport or not, you’ll be <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"136\">(17/18) given access to all our facilities (C: use of sports facilities)</strong> </span>which means you can have a swim or play a football match without having to pay anything.</p>\n<p data-path-to-node=\"12\">We have an internet cafe where there’s a small charge for access, and we also provide discounted meals in our canteen. We’ll <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"125\">(17/18) give everyone UK Summer Camp T-shirts (B)</strong></span>, which we’ll expect you to wear when working, and if you wish we also have some cool sports bags which are available for a small fee.</p>\n<p data-path-to-node=\"13\">So what do we expect from you? You’ll be glad to hear that we don’t need to see any formal certificates. If you’ve worked with kids before, that would be an advantage but it isn’t essential. Of course, you need to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"214\">(19/20) be sociable and enjoy meeting people (C: a friendly personality)</strong>. </span>There’ll always be a supervisor available who you should talk to before making any important decisions. We <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"13\" data-index-in-node=\"395\">(19/20) can’t accept applications from people under the age of 18 (E: to be over a certain age)</strong></span> I’m afraid, but if you haven’t got there yet, don’t worry, there’s always next time.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('de47b985-d8dc-4a5b-ba05-276556ec91a7', '3c753462-8c7a-41a6-b84a-926c7b5b4782', 'checkbox', 'Questions 17–18', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>beneﬁts are provided free of charge to camp workers?</p>
', 'multiple_choice_many', 'null', '[{"option": "a sports bag", "correct": false}, {"option": "a T-shirt", "correct": true}, {"option": "use of sports facilities", "correct": true}, {"option": "meals", "correct": false}, {"option": "internet access", "correct": false}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('92284cd6-9f74-4595-8ad1-dd46ae9d6cfe', '3c753462-8c7a-41a6-b84a-926c7b5b4782', 'checkbox', 'Questions 19–20', NULL, '<p>Choose <strong>TWO </strong>correct answers.</p>
<p>Which <strong>TWO </strong>things do applicants need in order to get a job at the camp?</p>
', 'multiple_choice_many', 'null', '[{"option": "experience of working with children", "correct": false}, {"option": "an ability to make decisions on their own", "correct": false}, {"option": "a friendly personality", "correct": true}, {"option": "relevant qualiﬁcations", "correct": false}, {"option": "to be over a certain age", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('0e169e48-75a0-4f57-9aec-de712c76981f', '64f6ee96-c0c2-4b89-b5e6-99cd133a57e5', 'matching', 'Questions 27-30', NULL, '<p>Choose the letters <strong>A</strong>–<strong>F </strong>in boxes 27-30.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A make things like clothes"}, {"optionText": "B produce plastic from plant"}, {"optionText": "C selling plastic in market"}, {"optionText": "D fermentation process"}, {"optionText": "E drape fabrics"}, {"optionText": "F wrapping products"}], "matchingItems": [{"questionPart": "scientists manage to", "correctAnswer": "B produce plastic from plant", "sectionContent": null}, {"questionPart": "Cargill needs to have contacts with", "correctAnswer": "C selling plastic in market", "sectionContent": null}, {"questionPart": "Nature work is used for", "correctAnswer": "F wrapping products", "sectionContent": null}, {"questionPart": "Ingeo is used to", "correctAnswer": "A make things like clothes", "sectionContent": null}]}', 'null', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">27. scientists manage to: B produce plastic from plant</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn A, câu 1: “scientists at Cargill got the idea of <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"65\">converting lactic acid made from corn into plastic</strong>…”</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích</strong>: “Corn” (ngô) là một loại thực vật (plant). Các nhà khoa học đã thành công trong việc chuyển đổi axit lactic từ ngô thành nhựa PLA.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. Cargill needs to have contacts with: C selling plastic in market</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu 2: “The company needed a partner with <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"61\">access to plastics markets</strong> and polymerization capabilities…”</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Để đưa sản phẩm ra thị trường, Cargill cần một đối tác có khả năng tiếp cận các thị trường nhựa (selling plastic in market), dẫn đến sự hợp tác với Dow Chemical.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. Nature Works is used for: F wrapping products</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu cuối: “Nature Works™ PLA is a family of <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"63\">packaging polymers</strong>…” và Đoạn G, câu cuối: “<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"108\">Packaging applications</strong> include packaging films and food and beverage containers.”</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Nature Works PLA là dòng polyme dùng cho đóng gói (packaging), tương đương với việc bao gói sản phẩm (wrapping products).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. Ingeo is used to: A make things like clothes</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu cuối: “<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"30\">Ingeo</strong> is a family of polymers for <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"64\">fibers</strong>…” và Đoạn G, câu 4: “<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"94\">Fiber</strong> and non-woven applications include <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"135\">clothing</strong>, fiberfill, blankets and wipes.”</li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Ingeo được sử dụng để tạo ra các loại sợi (fibers), và các ứng dụng của sợi này bao gồm việc sản xuất quần áo (clothing/make things like clothes).</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('8f4eddac-012b-4aa3-bd1d-7b5f856d8056', '83ae0844-3dd2-44ee-afc5-6a45d730600d', 'radio', 'Questions 36–40', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the views of the writer. <strong>NO </strong>if the statement contradicts what the writer thinks. <strong>NOT GIVEN </strong>if it is impossible to know what the writer’s point of view is.</p>
', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The emergence of Homer''s epic poetry occurred in the same historical period as the beginning of the Olympic Games."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The Italian scientists concluded that the motor actions encoded within the premotor cortex have no discernible link to unrelated collections of neurons."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Spectators can achieve flawless golf swings merely by watching the Masters Tournament without physical practice."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Some neuroscientists believe that certain types of still images might activate mirror neurons under specific experimental conditions."}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The mu system is suppressed while we are dynamically involved in a particular activity."}]', 'null', 'null', 'null', '[{"content": "<p><strong>36. The emergence of Homer’s epic poetry occurred in the same historical period as the beginning of the Olympic Games.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “<strong>During the epoch when the poet Homer unveiled his grand epic</strong>, the ancient Greeks <strong>initiated a festival… known as the Olympics</strong>…”</li>\n<li><strong>Giải thích:</strong> “During the epoch” (Trong cùng thời kỳ) xác nhận hai sự kiện diễn ra cùng thời điểm.</li>\n</ul>\n<p><strong>37. The Italian scientists concluded that the motor actions encoded within the premotor cortex have no discernible link to unrelated collections of neurons.</strong></p>\n<ul>\n<li><strong>Đáp án: NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “…novices rely on conscious effort, utilising <strong>brain regions adjacent to the premotor cortex</strong>.” (Vùng não liền kề vẫn tham gia.)</li>\n<li><strong>Giải thích:</strong> Các nhà khoa học Ý khám phá ra rằng premotor cortex chứa “grammar of movement” (Đoạn B), và việc người mới dùng các vùng não <strong>liền kề</strong> (adjacent) có thể hàm ý sự liên kết, mâu thuẫn với việc “không có liên kết”.</li>\n</ul>\n<p><strong>38. Spectators can achieve flawless golf swings merely by watching the Masters Tournament without physical practice.</strong></p>\n<ul>\n<li><strong>Đáp án: NO</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “It turns out that <strong>watching a remarkable golfer improves our own golfing skills</strong>…”</li>\n<li><strong>Giải thích:</strong> Việc xem có thể “cải thiện” (improves) kỹ năng, nhưng không khẳng định rằng việc này đủ để đạt được cú đánh <strong>hoàn hảo</strong> (flawless) <strong>chỉ bằng việc xem</strong> mà không cần luyện tập thể chất.</li>\n</ul>\n<p><strong>39. Some neuroscientists believe that certain types of still images might activate mirror neurons under specific experimental conditions.</strong></p>\n<ul>\n<li><strong>Đáp án: NOT GIVEN</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “If we stare at a photograph, a <strong>static image</strong> of a runner striding ahead, our mirror neurons <strong>remain utterly silent</strong>.”</li>\n<li><strong>Giải thích:</strong> Văn bản chỉ nói rằng hình ảnh tĩnh thông thường không kích hoạt neuron gương. <strong>Không có thông tin</strong> về việc các nhà thần kinh học có tin vào khả năng kích hoạt này dưới điều kiện thí nghiệm đặc biệt hay không.</li>\n</ul>\n<p><strong>40. The mu system is suppressed while we are dynamically involved in a particular activity.</strong></p>\n<ul>\n<li><strong>Đáp án: YES</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “The mu signal plays a role in neural mirroring, remaining active during periods of bodily stillness but <strong>dissipating when we undertake active pursuits</strong> like playing a sport or changing TV channels.”</li>\n<li><strong>Giải thích:</strong> “Dissipating” (tan biến) đồng nghĩa với bị “suppressed” (ức chế/triệt tiêu) khi chúng ta tham gia vào một hoạt động tích cực (dynamically involved).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('189ec524-932a-43be-8e57-9c435376c0f4', '3c523f98-9749-47dc-bca4-6e975a29317e', 'fillup', 'Questions 8–10', '<p data-start="654" data-end="729">Complete the notes below.</p>
<p data-start="654" data-end="729">Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p data-start="731" data-end="760"><span style="font-size: 14pt;"><strong>Details of Beading Class</strong></span></p>
<ul data-start="762" data-end="900">
<li data-start="762" data-end="806">
<p data-start="764" data-end="806">The first class starts on: {15 May| May 15th| 15th May | May 15}</p>
</li>
<li data-start="807" data-end="834">
<p data-start="809" data-end="834">Cost of the class: $100</p>
</li>
<li data-start="835" data-end="862">
<p data-start="837" data-end="862">Room No.: {J52}</p>
</li>
<li data-start="863" data-end="900">
<p data-start="865" data-end="900">Parking: next to a {station} </p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<div class=\"virtual-scroll-container model-prompt-container\" data-turn-role=\"Model\">\n<div class=\"turn-content\">\n<h1 class=\"ng-star-inserted\"><strong>DICTATION</strong></h1>\n<h3 class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">PART 1: PRESTON COMMUNITY CENTRE CLASSES</span></strong></h3>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Hello, this is Preston Community Centre.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Oh hello. My name is Andrew Shepherd. I’m ringing about the classes you offer.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Okay Mister Shepherd. Are there any classes in particular that you’re interested in?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Yes, you’ve got </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(1) ________________________________</span></strong><span class=\"ng-star-inserted\">, I believe?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> That’s right. It’s the first time we offer this class because many people inquired about it last term.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">It’ll be held in a library, not far from our community center.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Right. I know it’s on the weekend, right?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Yes, it’s on Saturday, and it will </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(2) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Okay, um… what do I need to bring?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Obviously, you have to bring your own camera. Some people bring a lot of accessories, like an extra lens, but there’s really no need for this class.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">It’s </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(3) ________________________________</span></strong><span class=\"ng-star-inserted\"> really, and getting the most out of the basic camera.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> That’s exactly what I want. Okay then, I’ve heard there’s a class on cooking, right?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Yes, it’s </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(4) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">As the name suggests, it will teach you cooking skills in French cuisine.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Oh great. Where will that be held?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> This class is special, so we arrange it in a kitchen where we can </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(5) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Let me see… yes, the Anita Kitchen.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">As for the time of the course, it used to be on the second Tuesday of every month,</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">but there’s a </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(6) ________________________________</span></strong><span class=\"ng-star-inserted\"> this time.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Although it’s still held on a monthly basis, the exact time will be </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(7) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Well actually, it’s my wife who’s really interested, and I think it’s a good fit for her</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">because our daughter has to take a guitar lesson every Tuesday, </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(8) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> That’s good. But I have to remind you that </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(9) ________________________________</span></strong><span class=\"ng-star-inserted\"> in this class,</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">so when you do come, please bring one with you in case you get dirty when cooking.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">What’s more, don’t forget to </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(10) ________________________________</span></strong><span class=\"ng-star-inserted\"> with you,</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">as the ingredients for cooking, like vegetables or meat, have to </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(11) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Okay, useful information to know. Then, there’s another class that my wife would like to join.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">That’s </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(12) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Oh, I’ve taken the class myself. The tutor is excellent.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Last term it was held in a tennis club, which is </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(13) ________________________________</span></strong><span class=\"ng-star-inserted\"> soon,</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">so we plan to change this class </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(14) ________________________________</span></strong><span class=\"ng-star-inserted\"> this time.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">And it’ll be held on the evening of every Wednesday.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Do I have to bring the beads with me?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Yes, that’s the </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(15) ________________________________</span></strong><span class=\"ng-star-inserted\"> for this class.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Okay, I think this class is also a good choice for her. Um, do you have any other classes that I can join?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> If you like, I think you can </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(16) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">It’s a popular class, so this term we’re going to move it to a high school so that we </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(17) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> What time will it be?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> It’ll be on every Monday evening.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> The time’s good for me. Do I have to bring the paints?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Well, paints will be provided by the tutor. I know that… um, the information says you’ll </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(18) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> I see.</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">DETAILS OF BEADING CLASS</span></strong></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Andrew:</span></strong><span class=\"ng-star-inserted\"> Okay, just another question about the beading class. I’ve just remembered my wife asked me to find out the exact time.</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">When will the first class begin?</span></p>\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">Staff:</span></strong><span class=\"ng-star-inserted\"> Well, the </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(19) ________________________________</span></strong><span class=\"ng-star-inserted\"> is April the 30th,</span></p>\n<p class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">and we’re not going to start the class </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">(20) ________________________________</span></strong><span class=\"ng-star-inserted\">.</span></p>\n<hr class=\"ng-star-inserted\">\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"> </h3>\n<h3 class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">ĐÁP ÁN (ANSWER KEY)</span></strong></h3>\n<ol class=\"ng-star-inserted\">\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">a class called Photography</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">occupy the whole morning</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">mainly focusing on composition</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">called French Cooking class</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">get the necessary cooking equipment</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">small adjustment this time</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">changed to the first Tuesday</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">so my wife is available</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">aprons are not provided</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">bring some money</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">be paid by yourself</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">the beading class</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">going to be redecorated</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">to a golf club</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">only material needed</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">take our painting class</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">can get more room</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">just need some brushes</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">deadline for registration</span></strong></p>\n</li>\n<li class=\"ng-star-inserted\">\n<p class=\"ng-star-inserted\"><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">until the 15th of May</span></strong><span class=\"ng-star-inserted\"> (hoặc </span><strong class=\"ng-star-inserted\"><span class=\"ng-star-inserted\">until 15 May</span></strong><span class=\"ng-star-inserted\">)</span></p>\n</li>\n</ol>\n</div>\n</div>"}]', 1);
INSERT INTO public.questions VALUES ('92f26c43-8770-4fcb-8aed-2fb049e12031', 'ca19f140-6fc3-4bb7-b56e-c264302b0b2c', 'matching', 'Questions 36-40', NULL, '<p>Complete the notes using the list of words, <strong>A-I</strong>, below.</p>
<p>Choose the correct letter, <strong>A-I</strong>, in boxes <strong>36-40</strong></p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><span style=\"font-size: 10pt;\"><strong>Sir Walter Scott and Robert Louis Stevenson</strong></span></p>\n<p>A lot of people believe that Sir Walter Scott and Robert Louis Stevenson are the most influential writer in the history of Scotland, but Sir Walter Scott is more proficient in {F. technical control} , while Stevenson has better {A. natural ability} Scott’s books illustrate {H. depth} especially in terms of tragedy, but a lot of readers prefer Stevenson’s {G. storytelling} What’s more, Stevenson’s understanding of {I. human nature} made his works have the most unique expression of Scottish people.</p>", "answerOptions": [{"optionText": "A. natural ability"}, {"optionText": "B. romance"}, {"optionText": "C. colorful language"}, {"optionText": "D. critical acclaim"}, {"optionText": "E. humor"}, {"optionText": "F. technical control"}, {"optionText": "G. storytelling"}, {"optionText": "H. depth"}, {"optionText": "I. human nature"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">36. {F} technical control</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 3: <em data-path-to-node=\"3,0,0\" data-index-in-node=\"26\">“While many critics exalt Sir Walter Scott as a literary genius because of his <strong data-path-to-node=\"3,0,0\" data-index-in-node=\"105\">technical ability</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong danh sách từ cho trước, <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"42\">technical control</strong> đồng nghĩa với <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"75\">technical ability</strong> (khả năng kỹ thuật/kiểm soát kỹ thuật). Đây là đặc điểm mà các nhà phê bình dùng để ca ngợi Sir Walter Scott.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">37. {A} natural ability</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 3: <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“…others argue that Stevenson deserves the same recognition for his <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"96\">natural ability</strong> to capture stories…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngược lại với Scott, Stevenson được công nhận nhờ vào <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"66\">khả năng thiên bẩm</strong> (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"86\">natural ability</strong>) trong việc truyền tải câu chuyện và nhân vật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38. {H} depth</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 4: <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Many of Scott’s works were taken more seriously as literature for their <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"99\">depth</strong> due to their tragic themes…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các tác phẩm của Scott được đánh giá cao về <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"56\">chiều sâu</strong> (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"67\">depth</strong>) văn học, đặc biệt là khi khai thác các chủ đề bi kịch.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. {G} storytelling</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 4: <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“…but fans of Stevenson praise his unique style of <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"79\">story-telling</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong khi Scott mạnh về chiều sâu bi kịch, độc giả lại yêu thích Stevenson vì phong cách <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"101\">kể chuyện</strong> (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"112\">storytelling</strong>) độc đáo của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">40. {I} human nature</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, câu 4: <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“…praise his unique style of story-telling and capture of <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"86\">human nature</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự thấu hiểu và khả năng nắm bắt <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"45\">bản chất con người</strong> (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"65\">human nature</strong>) là yếu tố giúp tác phẩm của Stevenson thể hiện một cách độc nhất về con người Scotland.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('fdff57c3-fbd1-4342-ac2b-53e5d696a4e5', '1ed10280-ddd8-4e0c-b4cd-41c6f5b7807f', 'matrix', 'Questions 14–18', '', '<p>The text has five paragraphs, <strong>A–E</strong>.</p>
<p>Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a description of a company that provides financial assistance for employees to continue their learning", "correctCategoryLetter": "B"}, {"itemText": "a mention of worldwide trends in the changing attitudes of businesses and customers", "correctCategoryLetter": "E"}, {"itemText": "details about years of continuous service by employees at one company", "correctCategoryLetter": "C"}, {"itemText": "a reference to the reason why many people-centered workers first start their own businesses", "correctCategoryLetter": "A"}, {"itemText": "a comment about how certain groups are still fighting for respect in the business world", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">14. A description of a company that provides financial assistance for employees to continue their learning — {B}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">pays,</span><span class=\"\"> at least partially,</span><span class=\"\"> for </span><strong class=\"\" data-path-to-node=\"4,0,0\" data-index-in-node=\"45\">educational opportunities and textbooks</strong><span class=\"\">.</span><span class=\"\">” (Đoạn B)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong class=\"\" data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Công ty Plastic Solutions của Stephen Harper hỗ trợ một phần chi phí giáo dục và sách giáo khoa cho nhân viên.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">15. A mention of worldwide trends in the changing attitudes of businesses and customers — {E}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Family-friendly entrepreneurs are becoming more </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"60\">commonplace internationally</strong><span class=\"\">…</span><span class=\"\"> parents are important </span><strong class=\"\" data-path-to-node=\"6,0,0\" data-index-in-node=\"113\">consumers and investors</strong><span class=\"\"> who can change buying practices.</span><span class=\"\">” (Đoạn E)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong class=\"\" data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn E nói về xu hướng quốc tế (worldwide trends) và vai trò của khách hàng (consumers) trong việc thay đổi hành vi mua sắm dựa trên chính sách gia đình của doanh nghiệp.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">16. Details about years of continuous service by employees at one company — {C}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “…</span><span class=\"\">this year the company will celebrate </span><strong class=\"\" data-path-to-node=\"8,0,0\" data-index-in-node=\"52\">six 5-year anniversaries, and one 25-year anniversary</strong><span class=\"\"> among its employees.</span><span class=\"\">” (Đoạn C)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong class=\"\" data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn C đưa ra số liệu cụ thể về thâm niên làm việc (số năm cống hiến liên tục) của nhân viên tại Margaret Mills Corporation.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">17. A reference to the reason why many people-centered workers first start their own businesses — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Many of these go into business themselves as a </span><strong class=\"\" data-path-to-node=\"10,0,0\" data-index-in-node=\"59\">result of negative experiences</strong><span class=\"\"> they have had in the workplace.</span><span class=\"\">” (Đoạn A)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong class=\"\" data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Jennifer West giải thích rằng nhiều chủ doanh nghiệp tự khởi nghiệp vì họ từng có những trải nghiệm không tốt (negative experiences) tại nơi làm việc cũ.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">18. A comment about how certain groups are still fighting for respect in the business world — {D}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong><span class=\"\"> “Working mothers still need to be </span><strong class=\"\" data-path-to-node=\"12,0,0\" data-index-in-node=\"45\">taken more seriously</strong><span class=\"\">,</span><span class=\"\"> and so do mothers who are business owners.</span><span class=\"\">” (Đoạn D)</span></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Hazel Gibbs đề cập đến việc những người mẹ đi làm hoặc làm chủ doanh nghiệp vẫn chưa được tôn trọng hoặc coi trọng đúng mức (</span><em class=\"\" data-path-to-node=\"12,1,0\" data-index-in-node=\"137\">taken seriously</em><span class=\"\">).</span></p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('6d5209dc-6c6a-4f14-a9cc-ff5f4c91b6a6', '1ed10280-ddd8-4e0c-b4cd-41c6f5b7807f', 'matrix', 'Questions 19–21', '', '<p>Choose the correct business person, <strong>A</strong>–<strong>E</strong>, for each statement.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of people", "matrixItems": [{"itemText": "Employees should be kept informed about business developments and performance", "correctCategoryLetter": "B"}, {"itemText": "Work output increases when employees have a good balance between company and family responsibilities", "correctCategoryLetter": "D"}, {"itemText": "It is critical to business success that all company members recognise that they matter", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "Jennifer West", "categoryLetter": "A"}, {"categoryText": "Stephen Harper", "categoryLetter": "B"}, {"categoryText": "Margaret Mills", "categoryLetter": "C"}, {"categoryText": "Victor Davies", "categoryLetter": "D"}, {"categoryText": "Hazel Gibbs", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">19. Employees should be kept informed about business developments and performance — {B: Stephen Harper}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…when his employees receive their salary, they also get an <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"73\">update about the company</strong>, including who their new customers are, what successes they’ve had…” (Đoạn B)</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">20. Work output increases when employees have a good balance… — {D: Victor Davies}</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “We enable employees to maintain equilibrium between work and home, a policy which ultimately results in a <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"118\">more productive</strong> and stable workforce.” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Productive” tương ứng với “work output increases”, và “equilibrium” tương ứng với “balance”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">21. It is critical to business success that all company members recognise that they matter — {E: Hazel Gibbs}</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…she works hard to ensure that everyone… <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"57\">realizes that they count</strong>.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “They count” (họ có giá trị/quan trọng) đồng nghĩa với “they matter”.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('bfc0c60d-ed90-43f0-a587-b1aad5f8da77', 'c9f8e19a-9d15-492a-8c4a-dc825b974dca', 'matching', 'Question 27-30', NULL, '<p>What is the main physical benefit of each of the following walking situations?<br />
Choose <strong>FOUR </strong>answers from the box and write the correct letter.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "A. improved balance"}, {"optionText": "B. greater stamina"}, {"optionText": "C. better eyesight"}, {"optionText": "D. lower blood pressure"}, {"optionText": "E. regular sleeping pattern"}, {"optionText": "F. stronger bones"}, {"optionText": "G. weight reduction"}], "matchingItems": [{"questionPart": "walking with thin-soled footwear", "correctAnswer": "F. stronger bones", "sectionContent": null}, {"questionPart": "walking in the mountains", "correctAnswer": "C. better eyesight", "sectionContent": null}, {"questionPart": "walking for the elderly", "correctAnswer": "E. regular sleeping pattern", "sectionContent": null}, {"questionPart": "walking long distances", "correctAnswer": "B. greater stamina", "sectionContent": null}]}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('f90b5ceb-b2ce-4b99-be82-6ed23ddc0d7a', '7ff11e44-f44a-4cef-a7fa-1b8af337f088', 'matching', 'Questions 27–31', NULL, '<p>Choose the correct heading for each paragraph from the list of headings below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Evidence of outdoor dwellings fire"}, {"optionText": "ii Learning to make"}, {"optionText": "iii A perfect place to live"}, {"optionText": "iv Examining the cave contents"}, {"optionText": "v Contrasting two types of home"}, {"optionText": "vi A vital source of power"}], "matchingItems": null}', 'null', '[{"content": "<p><strong>27. Paragraph A</strong></p>\n<ul>\n<li><strong>Đáp án: v. Contrasting two types of home</strong></li>\n<li><strong>Giải thích:</strong> Đoạn A đối chiếu hai loại nơi ở chính của người Neanderthal: <strong>caves</strong> (hang động) ở Tây Âu và <strong>open-air sites</strong> (nơi ở ngoài trời) ở phía Đông.</li>\n</ul>\n<p><strong>28. Paragraph B</strong></p>\n<ul>\n<li><strong>Đáp án: iii. A perfect place to live</strong></li>\n<li><strong>Giải thích:</strong> Đoạn B mô tả khu vực Périgord là <strong>“ideal homes”</strong> (ngôi nhà lý tưởng) với khí hậu ôn hòa, nguồn thức ăn dồi dào và bảo vệ tốt.</li>\n</ul>\n<p><strong>29. Paragraph C</strong></p>\n<ul>\n<li><strong>Đáp án: i. Evidence of outdoor dwellings fire</strong></li>\n<li><strong>Giải thích:</strong> Đoạn C nói về các địa điểm ngoài trời ở Đông Âu, nơi các nhà khảo cổ tìm thấy bằng chứng về <strong>wind-break structures</strong> (chỗ trú gió) và <strong>ash</strong> (tro) trong vòng xương voi ma mút (minh chứng cho lửa/nơi ở ngoài trời).</li>\n</ul>\n<p><strong>30. Paragraph D</strong></p>\n<ul>\n<li><strong>Đáp án: iv. Examining the cave contents</strong></li>\n<li><strong>Giải thích:</strong> Đoạn D chi tiết hóa các vật phẩm và cấu trúc được tìm thấy trong hang động (Grotte du Lazaret và Baume-Bonne): vỏ sò, xương thú, tro, đá cuội, lều da.</li>\n</ul>\n<p><strong>31. Paragraph E</strong></p>\n<ul>\n<li><strong>Đáp án: vi. A vital source of power</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “survival in the <strong>sub-arctic conditions</strong> faced by the Neanderthalers is <strong>inconceivable without control of fire</strong>.”</li>\n<li><strong>Giải thích:</strong> Lửa là thứ không thể thiếu (vital source of power) để sưởi ấm, nấu ăn và phòng thủ.</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('82e7062d-1108-4994-a0f9-064a7f2b34bd', '2a74ee27-fa90-4899-8f1a-1a0847b271aa', 'checkbox', 'Questions 25 and 26', '', '<p>Choose <strong data-path-to-node="5" data-index-in-node="27">TWO</strong> letters, <strong data-path-to-node="5" data-index-in-node="40">A-E</strong>.</p>
<p>Write the correct letters in boxes 25 and 26 on your answer sheet.</p>', 'multiple_choice_single', 'null', '[{"correct": true, "option_text": "A. Decision making is currently too concentrated at national level."}, {"correct": false, "option_text": "B. Local authorities must bear responsibility for past episodes of flooding."}, {"correct": true, "option_text": "C. Those responsible need to make choices about the allocation of financial resources."}, {"correct": false, "option_text": "D. Expert advice should be the deciding factor in any decisions."}, {"correct": false, "option_text": "E. Disagreements over land use are the main area of controversy."}]', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">25. Đáp án A: Decision making is currently too concentrated at national level.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…the <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"28\">current policy structure gives the federal government the most responsibility</strong> for floodplain management. It provides <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"145\">little incentive and few mechanisms for the county and municipal governments to help</strong>.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “National level” tương ứng với “Federal government” (Chính phủ liên bang). Tác giả chỉ ra rằng cấu trúc chính sách hiện tại đang dồn quá nhiều trách nhiệm và quyền quyết định lên cấp liên bang, trong khi cấp địa phương (quận, thành phố) lại có rất ít động lực hoặc cơ chế để tham gia. Điều này đồng nghĩa với việc quyền quyết định đang quá tập trung ở cấp quốc gia.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">26. Đáp án C: Those responsible need to make choices about the allocation of financial resources.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“In the end, all such policy decisions and the accompanying management actions must be based on <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"116\">people weighing up the costs and benefits of different spending priorities</strong>. In other words, they are <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"217\">political</strong>.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Allocation of financial resources” (Phân bổ nguồn lực tài chính) tương ứng với cụm “spending priorities” (các ưu tiên chi tiêu). Tác giả khẳng định rằng những người chịu trách nhiệm phải cân nhắc giữa chi phí và lợi ích để đưa ra lựa chọn về việc ưu tiên chi tiền vào đâu.</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('3f0cc418-de59-4f29-ad79-6c9512ed3d00', 'ecde7963-d53b-489b-87ef-32006e045dc8', 'matrix', 'Questions 17–22', '', '<p data-start="542" data-end="590">Match each event with the correct date, <strong data-start="582" data-end="589">A–H</strong>.</p>
<p data-start="592" data-end="663">Write the correct letter, <strong data-start="618" data-end="625">A–H</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of Dates", "matrixItems": [{"itemText": "An appeal for evidence of black-footed ferrets was published", "correctCategoryLetter": "B"}, {"itemText": "A scheme for releasing captive-born black-footed ferrets into the wild was launched", "correctCategoryLetter": "H"}, {"itemText": "The black-footed ferret first appeared in a scientific work", "correctCategoryLetter": "A"}, {"itemText": "The discovery of a single black-footed ferret led to renewed hope for the species", "correctCategoryLetter": "F"}, {"itemText": "North America''s last wild-born black-footed ferrets were taken into captivity", "correctCategoryLetter": "G"}, {"itemText": "Efforts to save the black-footed ferret were officially announced as having failed", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "1851", "categoryLetter": "A"}, {"categoryText": "1874", "categoryLetter": "B"}, {"categoryText": "1967", "categoryLetter": "C"}, {"categoryText": "1974", "categoryLetter": "D"}, {"categoryText": "1979", "categoryLetter": "E"}, {"categoryText": "1981", "categoryLetter": "F"}, {"categoryText": "1985", "categoryLetter": "G"}, {"categoryText": "1991", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">17. B (1874) — {An appeal for evidence of black-footed ferrets was published.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Then, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"27\">in 1874, a Dr Elliott Coues issued a request for specimens through the popular magazine</strong> The American Sportsman, and was soon rewarded.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"An appeal for evidence\" (Một lời kêu gọi tìm kiếm bằng chứng) đồng nghĩa với cụm từ \"issued a request for specimens\" (đưa ra yêu cầu cung cấp các mẫu vật). Hành động này được đăng tải công khai trên một tờ tạp chí nổi tiếng vào năm <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"245\">1874</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">18. H (1991) — {A scheme for releasing captive-born black-footed ferrets into the wild was launched.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn H):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">A reintroduction programme began in 1991</strong>. Before they can be <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"82\">reintroduced into their natural habitat, captive ferrets have to learn to hunt</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"A scheme for releasing... into the wild\" (Một chương trình thả/đưa động vật về tự nhiên) tương ứng hoàn toàn với thuật ngữ chuyên ngành \"A reintroduction programme\" (Chương trình tái du nhập/tái hòa nhập tự nhiên). Đối tượng của chương trình này là loài chồn sinh ra trong môi trường nuôi nhốt (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"308\">captive-born / captive ferrets</em>). Dự án này bắt đầu khởi động vào năm <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"377\">1991</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">19. A (1851) — {The black-footed ferret first appeared in a scientific work.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Black-footed ferrets <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"42\">were not officially recognized by scientists until 1851, when a description and drawing of one featured in a book</strong> by the renowned naturalist John James Audubon...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"First appeared in a scientific work\" (Lần đầu tiên xuất hiện trong một công trình nghiên cứu khoa học) tương ứng với việc được giới khoa học công nhận chính thức thông qua một bản mô tả và hình vẽ nằm trong một cuốn sách bách khoa của nhà tự nhiên học vào năm <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"273\">1851</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">20. F (1981) — {The discovery of a single black-footed ferret led to renewed hope for the species.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"21\">In 1981, a farm dog called Shep carried an odd-looking creature [a single black-footed ferret] to its owner''s ranch house</strong>... which <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"152\">led to efforts again being made to save the species</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The discovery of a single... ferret\" (Việc phát hiện ra một cá thể chồn duy nhất) diễn ra thông qua việc chú chó chăn trang trại tha cái xác về nhà. Việc này đã thắp lại hy vọng giải cứu (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"201\">renewed hope</em>) bằng cách kích hoạt lại các nỗ lực cứu lấy loài này (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"268\">led to efforts again being made</em>). Cột mốc này diễn ra vào năm <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"330\">1981</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">21. G (1985) — {North America''s last wild-born black-footed ferrets were taken into captivity.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"13,0,0\" data-index-in-node=\"21\">In 1985, in a final bid to save the species, the remaining 18 individuals in the colony were trapped for a new captive-breeding programme</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Wild-born ferrets\" (Những cá thể chồn sinh ra trong tự nhiên) tương ứng với cụm từ \"individuals in the colony\" (các cá thể trong quần thể hoang dã còn sót lại). Việc đưa chúng vào môi trường nuôi nhốt (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"215\">taken into captivity</em>) đồng nghĩa với hành động bẫy bắt chúng cho chương trình nhân giống nội vi (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"312\">trapped for a captive-breeding programme</strong>) vào năm <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"362\">1985</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">22. E (1979) — {Efforts to save the black-footed ferret were officially announced as having failed.}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“Finally, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"30\">in January 1979, the last ferret in a captive-breeding programme died — making the black-footed ferret the first mammal to be declared extinct</strong> in the Northern Hemisphere in the 20th century.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Efforts to save... officially announced as having failed\" (Các nỗ lực cứu vớt chính thức bị tuyên bố thất bại). Việc cá thể chồn cuối cùng trong chương trình nhân giống chết đi dẫn đến việc loài này bị tuyên bố tuyệt chủng (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"237\">declared extinct</strong>), đồng nghĩa với việc mọi nỗ lực bảo tồn trước đó đã hoàn toàn thất bại. Sự kiện đau lòng này diễn ra vào năm <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"364\">1979</strong>.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('90dafefc-5db4-400a-b09c-83833f1dd87a', '4e920fd6-4b7a-49b8-ad56-eae88315dd93', 'radio', 'Questions 21 - 26', '', '<p>Choose the correct letter, A B or C</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": " A her results section"}, {"option_text": "B her introductory chapter"}, {"option_text": "C her review of the literature"}], "question": " What part of Kathy''s dissertation has the tutor just read?"}, {"correct": 0, "options": [{"option_text": "A the organisation"}, {"option_text": "B the style of writing"}, {"option_text": "C the use of resources"}], "question": "What did the tutor like about Kathy''s work?"}, {"correct": 1, "options": [{"option_text": "A do some more library research."}, {"option_text": "B record more data."}, {"option_text": "C narrow down her topic."}], "question": "Kathy and the tutor agree that she needs to"}, {"correct": 2, "options": [{"option_text": "A to show how successful he has become"}, {"option_text": "B to illustrate how times have changed"}, {"option_text": "C. to encourage Kathy to do something similar"}], "question": "Why does the tutor give an example from his own experience?"}, {"correct": 2, "options": [{"option_text": "A layout."}, {"option_text": "B bibliography."}, {"option_text": "C appendices."}], "question": "Kathy would like the tutor to advise her on her"}, {"correct": 0, "options": [{"option_text": "A try out some software"}, {"option_text": "B go to a seminar"}, {"option_text": "C design a new type of pump"}], "question": "What is Kathy going to do next？"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: DISSERTATION DISCUSSION</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Tutor:</strong> Hello Kathy. How''s your dissertation on water pumps going?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Kathy:</strong> Not too bad, thanks. I''m getting on well with the literature review now, and my lab work''s fine so far.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Tutor:</strong> Oh, that''s good. Remember you should aim to have your results section completed by the end of next month, so there''s plenty of time to finalise the whole thing by the summer deadline. Anyway, looks like you''re on track. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"227\">(Q21) I''ve been through your first chapter now, and I was quite impressed.</strong></span></p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Kathy:</strong> Oh, that''s a relief!</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Tutor:</strong> Well, sometimes your sentences are a little long and over-complex, <strong data-path-to-node=\"7\" data-index-in-node=\"74\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q22) but the overall structure of the piece is very clear</span>.</strong> I''d recommend you get a critical friend to go through it with you. Then, once you''ve built in citations of other work in the field, I think it''ll be pretty good.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Kathy:</strong> Oh, thanks. I was pleased I decided to focus on water pumps.</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Tutor:</strong> You seem to be testing an appropriate range of pump designs. Lots of students make the mistake of either restricting their range too much or conversely, not narrowing it down enough. You''ve managed to avoid those twin traps. <strong data-path-to-node=\"9\" data-index-in-node=\"232\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q23) However, I think you''d get more convincing results if you took some additional measurements</span>.</strong> I''ve noted exactly what I mean on your work.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Kathy:</strong> Yes, I thought that might be necessary. And I know I need to get down to some more library work too.</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Tutor:</strong> Well, I don''t think that''s essential at the moment.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Kathy:</strong> Oh right. So what do you suggest I do next? Repeat my last experiment using different variables?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Tutor:</strong> Well, you could have a word with James Higgins tomorrow. He''s coming here to give a lecture on hydraulics to the faculty, and it would be a great chance to have a chat with him, especially as your experimental work has drawn so heavily from his last article in the British Engineering Journal.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Kathy:</strong> Oh, fantastic!</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Tutor:</strong> And you never know how successful a chat with him might turn out to be. <strong data-path-to-node=\"15\" data-index-in-node=\"79\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q24) I got my first research post when I was a final year student and asked a visiting professor to explain what he meant in some article he''d written</span>.</strong> So I urge all my students to take any such opportunity that arises.</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Kathy:</strong> Hmm, but times have changed. People like that are too busy to talk to mere students these days.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Tutor:</strong> I don''t know about that. Anyway, is there anything else I can help with? Any practical information about layout perhaps?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Kathy:</strong> Well, I suppose I''m a bit unsure about how the bibliography should be presented.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Tutor:</strong> Mm-hmm.</p>\n<p data-path-to-node=\"19\"><strong>Kathy:</strong> My dear, I can just check what''s normally done in journal articles, so that''s not something to bother you with.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Kathy:</strong> <strong data-path-to-node=\"20\" data-index-in-node=\"7\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q25) I''d welcome some guidance though about what I should or shouldn''t include in the appendices</span>.</strong> I know some things—some of my data tables or details of specs perhaps—are not really needed in the main body of the text, and I''m likely to be pushed for words there.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Tutor:</strong> Okay, I can certainly help you with that, but it will take a while, so can we deal with that next week? I''ve got that solar panel seminar to go into in a few minutes. There''s plenty of work you can be carrying on with in the meantime.</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Kathy:</strong> Sure, that''s no problem. <strong data-path-to-node=\"22\" data-index-in-node=\"32\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q26) I think I''ll go and investigate the latest version of the CAD software to see if it might help with my pump design experiments at all</span>.</strong></p>\n<hr data-path-to-node=\"23\">\n<h3 data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">CAREER ADVICE (Questions 27–30)</strong></h3>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Tutor:</strong> Before you go though, I''d like quickly to run through what you should be doing over the next few months not just for your dissertation, but also to help your chances of getting the research post you''d like. Is that okay with you?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Kathy:</strong> Yes, that would be really helpful.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Tutor:</strong> Well, you certainly need to become a member of the Mechanical Engineers'' Society and then you''ll be able to go along to their meetings. <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"27\" data-index-in-node=\"143\">(Q27) There you must make a point of making yourself known to various people like Professor Jones</strong></span>. He''s the current president and is very approachable.</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Kathy:</strong> OK, so I could do some <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"28\" data-index-in-node=\"30\">networking</strong></span> there?</p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Tutor:</strong> Exactly. Also I think you should try to set up some visits to industry. Go to a lot of different workplaces just to see how things are done. <strong data-path-to-node=\"29\" data-index-in-node=\"148\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q28) It''s actually a very good way of making sure you''re familiar with the cutting edge of what''s going on</span>.</strong> Textbooks, even academic articles, sometimes lag behind industry.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Kathy:</strong> That sounds really interesting. Also, I''d love the chance to do a bit of work abroad for a while.</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Tutor:</strong> Well, that''s actually the next thing I was going to recommend. <strong data-path-to-node=\"31\" data-index-in-node=\"70\"><span style=\"text-decoration: underline; background-color: #f1c40f;\">(Q29) I''m sure we could set up a month for you in either the States or Canada and that would be a great way to find out how things are done elsewhere</span>.</strong></p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Kathy:</strong> That should be good, thank you.</p>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">Tutor:</strong> And the last thing I was going to suggest was that you could go to the European Water Engineering conference being held in Spain in May.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Kathy:</strong> <span style=\"text-decoration: underline; background-color: #f1c40f;\"><strong data-path-to-node=\"34\" data-index-in-node=\"7\">(Q30) I could even present my dissertation there!</strong></span></p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Tutor:</strong> Yes!</p>\n<p data-path-to-node=\"35\"><strong>Kathy:</strong> Oh, thank you so much, that''s all really helpful.</p>\n<p data-path-to-node=\"35\"><strong>Tutor:</strong>  Good, so now if we pop...</p>"}]', 0);
INSERT INTO public.questions VALUES ('73d5e308-a96a-4f78-8953-ad439c548444', 'a73c6549-8c8e-4355-9425-19058dc8673b', 'checkbox', 'Questions 11 and 12', '', '<p data-path-to-node="16">Choose <strong data-path-to-node="16" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="16" data-index-in-node="20">A–E</strong>.</p>
<p data-path-to-node="17">Which <strong data-path-to-node="17" data-index-in-node="6">TWO</strong> problems with some training programmes for new runners does Liz mention?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A   There is a risk of serious injury."}, {"correct": false, "option_text": "B   They are unsuitable for certain age groups."}, {"correct": true, "option_text": "C   They are unsuitable for people with health issues."}, {"correct": false, "option_text": "D   It is difficult to stay motivated."}, {"correct": true, "option_text": "E   There is a lack of individual support."}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('43577410-fc3d-420b-acfb-048977aa47d2', 'ecde7963-d53b-489b-87ef-32006e045dc8', 'matrix', 'Questions 23–26', '', '<p>Reading Passage 2 has nine paragraphs, A–I.</p>
<p>Which paragraph contains the following information?</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "reasons for the sharp decrease in black-footed ferret populations", "correctCategoryLetter": "E"}, {"itemText": "the procedure by which black-footed ferrets are taught to survive in the wild", "correctCategoryLetter": "H"}, {"itemText": "mention of doubts about whether there was such an animal as a black-footed ferret", "correctCategoryLetter": "D"}, {"itemText": "reference to a site which is ideal for the release of black-footed ferrets into the wild", "correctCategoryLetter": "I"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Question 23:</strong> reasons for the sharp decrease in black-footed ferret populations</p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng :</strong> &gt; <em data-path-to-node=\"4,1,0\" data-index-in-node=\"26\">“As agriculture and ranching expanded, the black-footed ferret''s main prey, the prairie dog, became a target for extermination, and was eventually eradicated from 98% of its original range.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> <em data-path-to-node=\"4,2,0\" data-index-in-node=\"20\">target for extermination / eradicated</em> (mục tiêu tiêu diệt / bị xóa sổ 98%) chính là nguyên nhân dẫn đến sự sụt giảm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Question 24:</strong> the procedure by which black-footed ferrets are taught to survive in the wild</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">H</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &gt; <em data-path-to-node=\"7,1,0\" data-index-in-node=\"26\">“Before they can be reintroduced into their natural habitat, captive ferrets have to learn to hunt and escape from predators.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong>Giải thích:</strong> <em data-path-to-node=\"7,2,0\" data-index-in-node=\"20\">learn to hunt and escape</em> (học cách săn mồi và trốn kẻ thù) là nội dung tổng quát cho toàn bộ quy trình huấn luyện sinh tồn theo sau.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Question 25:</strong> mention of doubts about whether there was such an animal as a black-footed ferret</p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &gt; <em data-path-to-node=\"10,1,0\" data-index-in-node=\"26\">“For over two decades, no other specimens were seen, and scientists even began to question their existence.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong>Giải thích:</strong> <em data-path-to-node=\"10,2,0\" data-index-in-node=\"20\">question their existence</em> (đặt câu hỏi về sự tồn tại) thể hiện rõ nhất sự nghi ngờ về việc có loài vật này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Question 26:</strong> reference to a site which is ideal for the release of black-footed ferrets into the wild</p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">I</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &gt; <em data-path-to-node=\"13,1,0\" data-index-in-node=\"26\">“The Janos area on the US-Mexico border is the obvious place to reactivate the continent''s wild black-footed ferret population...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong>Giải thích</strong><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">:</strong> <em data-path-to-node=\"13,2,0\" data-index-in-node=\"20\">The Janos area / obvious place to reactivate</em> (Vùng Janos / nơi rõ ràng/thích hợp nhất để khôi phục lại) là địa điểm lý tưởng được nhắc tới.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('7e0eb368-0a70-4f66-9b10-9322807706be', 'a1b17802-2896-4448-9f9d-6ed91e1c216a', 'radio', 'Questions 11–14', NULL, '<p>Choose the correct answers</p>
<p><strong>Sports Information for Parents</strong></p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "the overall interest in sport has grown."}, {"content": "certain parents have given up these roles."}, {"content": "new types of sport are being introduced."}], "question": "The school is looking for new team coaches and managers because"}, {"correct": 1, "options": [{"content": "confidence about the rules of a particular sport"}, {"content": "the ability to make children enthusiastic about a sport"}, {"content": "commitment to training the team for a full season"}], "question": "What does the speaker say is the most important thing a coach needs?"}, {"correct": 0, "options": [{"content": "attend an upcoming registration event."}, {"content": "can commit to two coaching sessions per week."}, {"content": "have their own child in the team."}], "question": "For parents who would like to coach rugby, one requirement is that they"}, {"correct": 0, "options": [{"content": "pay a deposit at school."}, {"content": "ask the team manager for one."}, {"content": "visit the recommended local sports store."}], "question": "In order to get a netball uniform, parents will need to"}]', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>PART 2</strong></p>\n<p class=\"MsoNormal\"><strong>Assistant Principal:</strong> Good evening parents, and thank you for offering your help. I’m here to talk about the sports programs that the children are taking part in this term. Although we do do sport during class time, children often have extra activities before or after school or at weekends, and that’s when we need you.</p>\n<p class=\"MsoNormal\">First up, we’re looking for parents who would like to become team coaches or managers. We had some excellent people last year, but <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(11) some of those parents now have other commitments (B: given up these roles)</strong>.</span> It’s the Year 4 netball team, the Year 5 and 6 rugby teams, and the Year 3 hockey team that need new people.</p>\n<p class=\"MsoNormal\">Now coaching, I know some parents might not be completely familiar with, say, rugby or netball rules, but don’t let that put you off. Obviously knowledge of the game helps, but if you’re keen, there are some coaching courses you can take before the training sessions for players begin. What’s really required is the right attitude. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(12) Are you the kind of person that can motivate kids and make the game seem exciting? (B: ability to make children enthusiastic)</strong>.</span></p>\n<p class=\"MsoNormal\">All the rugby training and matches are organised by North Shore Rugby Club. If you do volunteer to become a rugby coach, you’ll need to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(13) go along to an important day that’s coming up—that’s on Saturday the 23rd (A: attend upcoming registration event)</strong>.</span> It takes place on the rugby grounds and it’s when all the kids put their names down for a team. Matches are on Saturday morning and training sessions on a Wednesday after school.</p>\n<p class=\"MsoNormal\">Moving on to netball matches and uniforms. Matches are on Monday at 4:00 PM. And for uniforms, we’ve just ordered a new set from the sports store in town, and <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(14) parents must hire one from the school secretary for $15, which gets refunded at the end of the season (A: pay a deposit at school)</strong>.</span></p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Assistant Principal:</strong> Okay, some of you are kindly helping with the cross-country running event. Children in years 3 to 6 will be running from school at the bottom of your map there. I’m going to point out some different places that need parent supervision.</p>\n<p class=\"MsoNormal\">The <strong><span style=\"text-decoration: underline; background-color: #ffe786;\">(15) drink station is one. If you’re handing out water, head to the north car park and the station will be set up on the other side of the road from it, right by the flag post (C).</span></strong></p>\n<p class=\"MsoNormal\">Two or three parents will be needed to help out at the major <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(16) crossing point</strong>,</span> just to make sure everybody’s going the right way. So on the map, there’s that little footpath going up past the school, then it splits into three directions.<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>The crossing point is at the end of the left-hand path heading west, just before you cross Summer Street (H)</strong>.</span></span></p>\n<p class=\"MsoNormal\">Now we’ll need a couple of parents at the <strong><span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\">(17) halfway point</span></span></strong> to send the children in the right direction. So there are four buildings on the far left-hand side. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>The halfway point is just to the right of these buildings (B)</strong>.</span></p>\n<p class=\"MsoNormal\">Okay, the teacher at our <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(18) first aid</strong></span> post might need help sticking plasters on. <strong><span style=\"text-decoration: underline; background-color: #ffe786;\">The quickest way to get to first aid is to head up the footpath next to school and when you get to the second turning on the right, head down there and it’s sort of opposite the satellite dish (F).</span></strong></p>\n<p class=\"MsoNormal\">What else? <span style=\"background-color: #ffe786;\"><strong><span style=\"text-decoration: underline;\">The (19) rest area is for children needing a break, and that’s the place nearest the south car park, near the road (G).</span></strong></span></p>\n<p class=\"MsoNormal\">And if any parent here is handy with a video camera, we’d really appreciate some help with filming the event. For the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(20) filming area</strong></span><span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>, this means heading up the footpath by the school, then keep going up with the flag post on your left and the satellite dish on your right, and the filming spot is just there, in front of the trees (D).</strong></span></span></p>\n<p class=\"MsoNormal\">Well, I think that covers everything…</p>\n"}]', 0);
